package reseq

import (
	"net/netip"
	"sync"
	"time"
)

// Clock is the injected time source. Production wires a monotonic wall clock
// (SystemClock); tests wire a hand-advanced fake so ordering, window, and
// timeout behaviour are deterministic with no real sleeps. It is intentionally
// structurally identical to telemetry.Clock so the same fake can drive both.
type Clock interface {
	Now() time.Time
}

// SystemClock is the production Clock backed by the monotonic wall clock.
type SystemClock struct{}

// Now returns the current monotonic time.
func (SystemClock) Now() time.Time { return time.Now() }

// Discontinuity/resync guard tuning. A DATA frame is UNAUTHENTICATED by design
// (internal/frame/frame.go: "DATA/PARITY forgeable by design"), so a garbage
// datagram decoding as KindData (p ~ 1/256) delivers a uniformly-random uint64
// OuterSeq, and a genuine peer PROCESS RESTART resets the peer's outerSeq counter
// to 1. Neither may be trusted to move the release point arbitrarily.
const (
	// resyncFactor (K) bounds how far AHEAD of the release point a single
	// unauthenticated frame is trusted to advance the window as a plausible loss
	// burst. Under bounded cross-path reorder a legitimate frame sits within one
	// window of next; a forward jump up to K windows is still treated as a loss
	// burst (the sound bounded-memory window-advance handles it in O(window)), but
	// a jump of K windows or more is SUSPECT: a single such frame never advances
	// next. K=4 leaves generous headroom above the 1-window reorder bound while
	// capping the release point a single trusted frame can skip to (K-1) windows.
	resyncFactor = 4

	// resyncCorroborate (C) is how many out-of-band frames carrying DISTINCT seqs
	// that mutually span less than one window must be observed before the release
	// point is re-pinned. A genuine peer restart (1,2,3,...) or a consistent
	// long-outage forward jump emits connected, distinct seqs that trivially
	// corroborate. A repeated identical seq does NOT advance the count: a single
	// junk or forged datagram re-delivered — a network duplicate, or a forger
	// replaying one datagram — contributes only ONE distinct seq, so it can never
	// self-corroborate. Corroboration therefore requires C INDEPENDENT junk seqs to
	// land mutually within one window; each is independent in 2^64, so that occurs
	// with probability ~(window/2^64)^(C-1) ~ 1e-32 for C=3 and window=2048 — junk
	// never triggers a resync, while a real discontinuity resyncs after losing at
	// most C-1 frames. Any in-band (near-current) frame resets the run, so ordinary
	// traffic interspersed with rare junk never accumulates a false corroboration.
	resyncCorroborate = 3
)

// Item is one released inner datagram plus the outer source address of the DATA
// frame that carried it. The source travels with the payload so the multipath
// Bind can pin its single virtual endpoint to the FIRST delivered frame's
// source even when that frame was buffered and released out of arrival order.
type Item struct {
	Payload []byte
	Src     netip.AddrPort
}

// slot is one ring cell. A live cell (occupied) holds exactly one buffered DATA
// frame whose OuterSeq maps to this index; seq is retained so a stale cell (an
// already-drained seq that shares the index modulo window) is never mistaken for
// a live one.
type slot struct {
	seq      uint64
	src      netip.AddrPort
	payload  []byte
	occupied bool
}

// Resequencer is a bounded-window, timeout-based receive resequencing buffer. It
// consumes DATA frames tagged with the multipath codec's OWN outer sequence
// number (frame.Data.OuterSeq — never WireGuard's inner counter) arriving out of
// order across paths, and releases the decoded inner datagrams in strictly
// ascending outer-seq order before they reach the WireGuard engine. This absorbs
// multipath reorder entirely in the outer layer so WG's RFC 6479 anti-replay
// filter (window 8128, see docs/p0-findings.md §6) only ever sees monotonically
// increasing inner counters and never drops a legitimately-delivered packet.
//
// Guarantees (see the package tests):
//   - Ordering: released frames are strictly ascending in outer-seq. A frame
//     whose seq is below the release point is dropped, never delivered late, so
//     delivery is monotonic and WG sees no replay-window regression.
//   - Exactly-once: duplicates (same seq re-observed before or after release) are
//     dropped; every deliverable frame is released exactly once.
//   - Bounded memory: at most `window` frames are buffered. A frame at or beyond
//     next+window forces the window to advance (releasing/skipping the tail),
//     so an adversarial reorder/loss trace cannot grow the buffer without bound.
//   - Timeout progress: when the head-of-line seq is missing, buffered frames
//     ahead of the gap are held at most `timeout`; then the gap is skipped
//     (treated as lost) and the run released, rather than stalling forever. Each
//     distinct head-of-line gap gets its OWN full timeout.
//   - Bounded compute: every Observe runs in O(window). No frame — however wild
//     its (unauthenticated, possibly forged) seq — can make the release point
//     advance one seq at a time across a gap of up to 2^64 under the mutex.
//   - Discontinuity resilience: an unauthenticated frame whose seq lies farther
//     than resyncFactor*window from next never moves the release point on its own.
//     A genuine peer restart or long outage — a run of frames carrying DISTINCT
//     seqs that mutually fall within one window — re-pins (resyncs) the release
//     point within a bounded number of frames; uniformly-random junk seqs, and a
//     single junk/forged seq re-delivered any number of times, do not.
//
// Concurrency: every method is guarded by one mutex, so the shared instance is
// safe for the multipath Bind's per-path receive goroutines. The mutex is held
// only for in-memory bookkeeping — never across a syscall — so it does not
// perturb the Bind's lock-free virtual-endpoint fast path or its
// syscall-outside-mutex send discipline.
//
// FEC seam (T24): Observe is the sole ingestion point and is keyed purely by
// outer-seq. An FEC decoder inserted on the receive path recovers missing DATA
// frames from PARITY and feeds each recovered frame's ORIGINAL outer-seq through
// Observe, identically to a natively-received frame — so FEC recovery slots in
// BEFORE resequencing with no change to this type.
type Resequencer struct {
	window  uint64
	timeout time.Duration
	clock   Clock

	mu      sync.Mutex
	started bool   // false until the first Observe pins the initial next
	next    uint64 // lowest outer-seq not yet released
	ring    []slot // len == window; indexed by seq % window
	buf     int    // number of occupied slots

	ready    []Item // FIFO of released items awaiting Pop
	readyPos int    // read cursor into ready (front of the FIFO)

	// Head-of-line timeout: when next is a gap but frames ahead are buffered,
	// waiting is armed with a deadline measured from when the gap first formed.
	waiting  bool
	deadline time.Time

	// Discontinuity/resync guard: the current run of out-of-band (suspect) frames.
	// resyncSeqs holds the DISTINCT suspect seqs seen in the run (a repeated
	// identical seq does not advance corroboration); [resyncLo, resyncHi] is the
	// run's seq span. When resyncSeqs reaches resyncCorroborate distinct seqs the
	// run is deemed a real discontinuity and the release point re-pins (see
	// tryResync). It holds at most resyncCorroborate seqs, so memory stays bounded.
	resyncSeqs []uint64
	resyncLo   uint64
	resyncHi   uint64

	// Diagnostics (read via the accessors; useful for the bounded-memory asserts).
	highWater   int    // max occupied slots ever held
	dropDup     uint64 // frames dropped as duplicates
	dropLate    uint64 // frames dropped as already-past the release point
	dropSuspect uint64 // out-of-band frames dropped while (not yet) corroborating
	skipped     uint64 // seqs skipped (treated lost) by window-advance or timeout
	releasedN   uint64 // frames released for delivery
	resyncs     uint64 // release-point re-pins after a corroborated discontinuity
	rebaselines uint64 // release-point re-baselines forced by a trusted control event (hub failover)
}

// New returns a resequencer buffering at most window outer-seq positions and
// holding a head-of-line-blocked run for at most timeout before skipping the gap.
// window must be positive; timeout may be zero (a missing head seq is skipped as
// soon as the next Observe/Pop advances the clock past the arrival instant).
func New(window uint64, timeout time.Duration, clock Clock) *Resequencer {
	if window == 0 {
		panic("reseq: window must be positive")
	}
	if clock == nil {
		panic("reseq: clock must be non-nil")
	}
	return &Resequencer{
		window:  window,
		timeout: timeout,
		clock:   clock,
		ring:    make([]slot, window),
	}
}

// Observe ingests one DATA frame's inner payload under its outer-seq. It takes
// ownership of payload (the caller must not mutate it afterwards); the multipath
// Bind passes the freshly-decoded frame.Data.Payload, which aliases nothing else.
// src is the outer source address the frame arrived from. Any frames that become
// deliverable are appended to the ready FIFO for Pop.
func (r *Resequencer) Observe(seq uint64, payload []byte, src netip.AddrPort) {
	now := r.clock.Now()
	r.mu.Lock()
	defer r.mu.Unlock()

	if !r.started {
		r.started = true
		r.next = seq
	}

	// Give up on any head-of-line gap whose hold time has elapsed before deciding
	// where this frame lands.
	r.expire(now)

	// Classify the frame against the release window and the discontinuity guard.
	// admit adjusts next (window-advance or resync) when warranted and reports
	// whether the frame now lands inside [next, next+window) and should be placed.
	if !r.admit(seq) {
		return
	}

	cell := &r.ring[seq%r.window]
	if cell.occupied && cell.seq == seq {
		r.dropDup++
		return
	}
	cell.seq = seq
	cell.src = src
	cell.payload = payload
	cell.occupied = true
	r.buf++
	if r.buf > r.highWater {
		r.highWater = r.buf
	}

	r.drain()
	r.arm(now)
}

// ObserveRecovered ingests a payload the FEC decoder reconstructed from parity (T24).
// Unlike Observe it NEVER moves or re-pins the release point: a recovered frame is a
// REPAIR for a past gap, so if it has already fallen below the release point it is
// dropped as too-late, and it can neither window-advance nor corroborate a resync — so
// FEC recovery can never CAUSE the burst loss it exists to prevent (a late batch of K
// recovered seqs below `next` must not be able to dump the live buffer via a backward
// resync). It returns whether the frame was PLACED (landed at or above the release
// point and will be delivered in order); a dropped-late recovered frame returns false,
// which the datapath uses to keep the /metrics recovered counter honest — counting
// frames actually delivered ahead of the release point, not merely reconstructed.
func (r *Resequencer) ObserveRecovered(seq uint64, payload []byte, src netip.AddrPort) bool {
	now := r.clock.Now()
	r.mu.Lock()
	defer r.mu.Unlock()

	if !r.started {
		r.started = true
		r.next = seq
	}
	r.expire(now)

	// The placement window is EXACTLY [next, next+window). A recovered frame below next
	// is too late (drop, and — crucially — never feed the resync guard). One at or beyond
	// next+window would require a window-advance we refuse to perform for a reconstructed
	// frame, since that would skip live seqs on the strength of a repair. Neither branch
	// touches next or the corroboration run.
	if seq < r.next {
		if r.next-seq > r.window {
			r.dropSuspect++
		} else {
			r.dropLate++
		}
		return false
	}
	if seq-r.next >= r.window {
		r.dropLate++
		return false
	}

	cell := &r.ring[seq%r.window]
	if cell.occupied && cell.seq == seq {
		r.dropDup++
		return false // already buffered (a received frame or a prior recovery)
	}
	cell.seq = seq
	cell.src = src
	cell.payload = payload
	cell.occupied = true
	r.buf++
	if r.buf > r.highWater {
		r.highWater = r.buf
	}

	r.drain()
	r.arm(now)
	return true
}

// admit classifies seq against the release window and the discontinuity guard and
// decides whether the frame should be buffered. It returns true when seq now lies
// inside [next, next+window) and should be placed; false (having bumped the
// appropriate drop counter) when the frame is dropped. It may advance next by a
// bounded amount on a plausible loss burst, or re-pin next on a corroborated
// discontinuity. Caller holds r.mu.
func (r *Resequencer) admit(seq uint64) bool {
	if seq < r.next {
		// Below the release point. A frame more than one window below next is
		// impossibly late under bounded reorder — treat it as SUSPECT (a peer
		// restart resets outerSeq to 1, so its frames land here). A frame within a
		// window below next is an ordinary straggler/duplicate.
		if r.next-seq > r.window {
			if r.tryResync(seq) {
				return true
			}
			r.dropSuspect++
			return false
		}
		r.resyncReset() // near-current traffic: not a discontinuity
		r.dropLate++
		return false
	}
	// seq >= next.
	if seq-r.next >= resyncFactor*r.window {
		// Too far ahead to be a plausible loss burst — SUSPECT (garbage-decoded or
		// forged high seq). A single such frame must not advance next.
		if r.tryResync(seq) {
			return true
		}
		r.dropSuspect++
		return false
	}
	// In-window, or a moderate (plausible loss-burst) forward jump: legitimate
	// near-current traffic, so any in-progress discontinuity run is broken.
	r.resyncReset()
	if seq-r.next >= r.window {
		// Beyond the window: advance the release point so the frame fits at the top
		// of the window, releasing buffered frames below the new base in order and
		// skipping the (assumed lost) gaps. This is what bounds memory.
		r.advanceTo(seq - r.window + 1)
	}
	return true
}

// Pop returns the next in-order released inner datagram, or ok=false when none is
// ready. It also advances the head-of-line timeout, so a receive goroutine that
// only drains still makes timeout progress.
func (r *Resequencer) Pop() (Item, bool) {
	now := r.clock.Now()
	r.mu.Lock()
	defer r.mu.Unlock()

	r.expire(now)

	if r.readyPos >= len(r.ready) {
		return Item{}, false
	}
	it := r.ready[r.readyPos]
	r.ready[r.readyPos] = Item{} // release the payload reference
	r.readyPos++
	if r.readyPos >= len(r.ready) {
		// FIFO drained: reset to reuse the backing array, keeping it bounded.
		r.ready = r.ready[:0]
		r.readyPos = 0
	}
	return it, true
}

// drain releases the contiguous run starting at next into the ready FIFO. Caller
// holds r.mu.
func (r *Resequencer) drain() {
	for {
		cell := &r.ring[r.next%r.window]
		if !cell.occupied || cell.seq != r.next {
			return
		}
		r.release(cell)
		r.next++
	}
}

// advanceTo moves next up to target, releasing any occupied cell it passes (in
// ascending order) and counting the empty positions as skipped (lost) seqs. It is
// O(window), NEVER O(target-next): all occupied cells live in [next, next+window),
// so once next reaches next+window the remaining gap is provably empty and is
// closed by arithmetic rather than iterated. Caller holds r.mu; target must be
// > next.
func (r *Resequencer) advanceTo(target uint64) {
	// Only [next, next+window) can hold occupied cells; iterate at most that far.
	limit := target
	if limit > r.next+r.window {
		limit = r.next + r.window
	}
	for r.next < limit {
		cell := &r.ring[r.next%r.window]
		if cell.occupied && cell.seq == r.next {
			r.release(cell)
		} else {
			r.skipped++
		}
		r.next++
	}
	if r.next < target {
		// The remaining gap [next, target) is entirely empty — no occupied cell can
		// live a full window ahead of the old release point. Close it by arithmetic.
		r.skipped += target - r.next
		r.next = target
	}
}

// release moves one occupied cell's payload into the ready FIFO and clears it.
// Caller holds r.mu.
func (r *Resequencer) release(cell *slot) {
	r.ready = append(r.ready, Item{Payload: cell.payload, Src: cell.src})
	cell.occupied = false
	cell.payload = nil
	r.buf--
	r.releasedN++
}

// expire skips a head-of-line gap whose hold time has elapsed: it jumps next to
// the smallest buffered seq (treating the intervening seqs as lost) and releases
// the now-contiguous run. Caller holds r.mu.
func (r *Resequencer) expire(now time.Time) {
	if !r.waiting || now.Before(r.deadline) {
		return
	}
	minSeq, ok := r.smallestBuffered()
	if !ok {
		r.waiting = false
		return
	}
	// Skip the lost gap [next, minSeq), then release from minSeq onward.
	for r.next < minSeq {
		r.skipped++
		r.next++
	}
	r.drain()
	// Clear the armed state BEFORE re-arming so that a distinct SECOND gap exposed
	// by this release gets its own full timeout rather than inheriting this gap's
	// already-elapsed deadline (which would skip it with ~zero hold).
	r.waiting = false
	r.arm(now)
}

// arm (re)evaluates the head-of-line timeout after a change. When next is a gap
// but buffered frames sit ahead of it, it starts the hold clock (only if not
// already running, so the deadline measures from when the gap first formed).
// Otherwise it disarms. Caller holds r.mu.
func (r *Resequencer) arm(now time.Time) {
	cell := &r.ring[r.next%r.window]
	headPresent := cell.occupied && cell.seq == r.next
	if !headPresent && r.buf > 0 {
		if !r.waiting {
			r.waiting = true
			r.deadline = now.Add(r.timeout)
		}
	} else {
		r.waiting = false
	}
}

// tryResync feeds one out-of-band (suspect) seq into the discontinuity guard. It
// re-pins the release point ONLY after resyncCorroborate DISTINCT suspect seqs
// whose values mutually span less than one window (a genuine peer restart or long
// outage emits connected, distinct seqs that corroborate; uniformly-random junk
// seqs, each independent in 2^64, do not, and a single junk/forged seq re-delivered
// contributes only ONE distinct value so it can never self-corroborate). It
// returns true and performs the resync when the corroboration threshold is met —
// re-pinning next to the triggering seq so the caller places it as the new head
// and delivery resumes immediately, without a phantom gap or an extra timeout —
// and false while still collecting or when the seq fails to corroborate the
// current run. Caller holds r.mu.
func (r *Resequencer) tryResync(seq uint64) bool {
	if len(r.resyncSeqs) == 0 || r.spanExceeds(seq) {
		// Start (or restart) the run at this seq: it does not corroborate the
		// current run, so it becomes the anchor of a fresh one.
		r.resyncLo, r.resyncHi = seq, seq
		r.resyncSeqs = append(r.resyncSeqs[:0], seq)
		return false
	}
	if r.runContains(seq) {
		// A repeated identical seq does NOT advance corroboration: a lone junk or
		// forged datagram re-delivered must not count as independent corroboration.
		return false
	}
	if seq < r.resyncLo {
		r.resyncLo = seq
	}
	if seq > r.resyncHi {
		r.resyncHi = seq
	}
	r.resyncSeqs = append(r.resyncSeqs, seq)
	if len(r.resyncSeqs) < resyncCorroborate {
		return false
	}
	// Corroborated discontinuity: re-pin to the triggering seq and resume delivery.
	r.resync(seq)
	return true
}

// runContains reports whether seq is already one of the distinct suspect seqs in
// the current corroboration run. The run holds at most resyncCorroborate seqs, so
// this scan is O(C). Caller holds r.mu.
func (r *Resequencer) runContains(seq uint64) bool {
	for _, s := range r.resyncSeqs {
		if s == seq {
			return true
		}
	}
	return false
}

// spanExceeds reports whether adding seq to the current corroboration run would
// make its seq span reach or exceed one window (i.e. seq does not mutually fall
// within one window of the run so far). Caller holds r.mu.
func (r *Resequencer) spanExceeds(seq uint64) bool {
	lo, hi := r.resyncLo, r.resyncHi
	if seq < lo {
		lo = seq
	}
	if seq > hi {
		hi = seq
	}
	return hi-lo >= r.window
}

// resync re-pins the release point to base after a confirmed discontinuity,
// discarding all buffered frames (they belong to the pre-discontinuity stream) in
// O(window). The already-released FIFO is untouched — those were legitimate prior
// deliveries. Caller holds r.mu.
func (r *Resequencer) resync(base uint64) {
	for i := range r.ring {
		r.ring[i] = slot{}
	}
	r.buf = 0
	r.next = base
	r.waiting = false
	r.resyncReset()
	r.resyncs++
}

// resyncReset abandons the current corroboration run. Caller holds r.mu.
func (r *Resequencer) resyncReset() {
	r.resyncSeqs = r.resyncSeqs[:0]
	r.resyncLo = 0
	r.resyncHi = 0
}

// Rebaseline discards the buffered (pre-switch) frames and UNPINS the release
// point so the NEXT Observe re-anchors `next` to that frame's outer-seq, exactly as
// if the stream had just started. It exists for the edge-side HUB FAILOVER (T57): a
// concentrator switch changes the DATA-frame SENDER, and the standby is a separate
// process whose outer-seq restarts near 1 — far below the release point the prior
// hub's high-rate stream advanced `next` to. The unauthenticated tryResync path
// cannot rescue this in time: it needs resyncCorroborate (3) distinct low seqs
// within one window, but a freshly re-handshaking standby emits only ~1 DATA frame
// (the handshake response) per RekeyTimeout, so corroboration falls outside the
// failover window and the response is dropped as SUSPECT — the tunnel never
// re-establishes (defect D32). Unlike a DATA frame (forgeable by design, hence the
// corroboration guard), THIS re-pin is driven by a TRUSTED control event — the
// operator-configured ordered-endpoint switch, above the unauthenticated wire — so
// re-anchoring on the next single frame is sound. Buffered frames (from the dead
// prior hub) are discarded in O(window); the already-released FIFO of prior
// legitimate deliveries is untouched. Idempotent and safe before the first Observe
// (started stays false). Takes r.mu; the caller must NOT hold it.
func (r *Resequencer) Rebaseline() {
	r.mu.Lock()
	defer r.mu.Unlock()
	for i := range r.ring {
		r.ring[i] = slot{}
	}
	r.buf = 0
	r.started = false
	r.waiting = false
	r.resyncReset()
	r.rebaselines++
}

// smallestBuffered scans the ring for the lowest occupied seq at or above next.
// All occupied seqs lie in [next, next+window), so this is bounded by window and
// runs only on the (rare) timeout path. Caller holds r.mu.
func (r *Resequencer) smallestBuffered() (uint64, bool) {
	best := uint64(0)
	found := false
	for i := range r.ring {
		c := &r.ring[i]
		if c.occupied && c.seq >= r.next && (!found || c.seq < best) {
			best = c.seq
			found = true
		}
	}
	return best, found
}

// Buffered reports the number of frames currently held (not yet released). It is
// always <= window, which the bounded-memory tests assert.
func (r *Resequencer) Buffered() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.buf
}

// Pending reports the number of released-but-not-yet-popped items in the FIFO.
func (r *Resequencer) Pending() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return len(r.ready) - r.readyPos
}

// HighWater reports the maximum number of frames ever buffered simultaneously.
func (r *Resequencer) HighWater() int {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.highWater
}

// Stats is a snapshot of the resequencer's cumulative counters.
type Stats struct {
	Released       uint64 // frames released for delivery
	DroppedDup     uint64 // frames dropped as duplicates
	DroppedOld     uint64 // frames dropped as already-past the release point
	DroppedSuspect uint64 // out-of-band frames dropped while (not yet) corroborating
	Skipped        uint64 // seqs skipped (lost) by window-advance or timeout
	Resyncs        uint64 // release-point re-pins after a corroborated discontinuity
	Rebaselines    uint64 // release-point re-baselines forced by a trusted control event (hub failover)
}

// Stats returns a snapshot of the cumulative counters.
func (r *Resequencer) Stats() Stats {
	r.mu.Lock()
	defer r.mu.Unlock()
	return Stats{
		Released:       r.releasedN,
		DroppedDup:     r.dropDup,
		DroppedOld:     r.dropLate,
		DroppedSuspect: r.dropSuspect,
		Skipped:        r.skipped,
		Resyncs:        r.resyncs,
		Rebaselines:    r.rebaselines,
	}
}

package sched

import (
	"github.com/7mind/wanbond/internal/telemetry"
)

// Negative Pick sentinels. Pick returns a NON-NEGATIVE path index when a datagram
// should egress, and one of these when it should not. They are distinct so the Send
// path can tell a genuine outage (no eligible path) apart from a transient pacer
// shedding a frame while every path is healthy — the two must not read the same in
// operator logs or the e2e log-grep harness.
const (
	// PickNone means no path is currently eligible (a total outage among this
	// scheduler's paths). The Bind maps it to "no healthy path".
	PickNone = -1
	// PickPaced means eligible paths EXIST but every one is momentarily paced out, so
	// this frame is shed (dropped) to bound egress and the send backlog. The paths are
	// healthy — this is deliberate rate limiting, NOT an outage. Only a pacing-enabled
	// weighted scheduler ever returns it.
	PickPaced = -2
)

// FrameClass tags an outbound datagram with the traffic class the pacer must treat
// it as (defect D22). The multipath Bind classifies each frame from the inner
// WireGuard message type and passes the class to Pick so a pacing scheduler can give
// WireGuard control frames (handshake init/response, cookie reply, keepalive) a
// different admission policy than bulk data. Pick() has no other frame-type
// visibility, so this is the ONLY channel by which frame-type reaches the pacer.
type FrameClass uint8

const (
	// ClassData is bulk/opaque data (a WireGuard transport datagram carrying tunnelled
	// payload). It is fully paced: under a weighted scheduler with pacing enabled it is
	// subject to the per-path token buckets and is shed (PickPaced) when they are empty.
	ClassData FrameClass = iota
	// ClassControl is a WireGuard control frame — handshake initiation/response, cookie
	// reply, or keepalive. It is pacing-EXEMPT: a pacing scheduler never sheds it for an
	// empty token bucket and never spends a data token for it, so sustained bulk overload
	// cannot starve rekey (defect D22). Control frames originate from OUR OWN WireGuard
	// engine on the send path (an attacker cannot inject them here), and WireGuard's own
	// state machine bounds their rate, so exempting them from the data pace is safe.
	ClassControl
)

// Scheduler is the send-side path-selection policy the multipath Bind consults
// for every outbound datagram. It is the extension seam for the send scheduler:
// active-backup failover (ActiveBackup, the P1 MVP) is one implementation; the
// later weighted / FEC-aware policy (T21) is a DIFFERENT implementation of this
// same interface, swapped in at the composition root with no Bind change.
type Scheduler interface {
	// Pick returns the index of the path the next datagram must egress on, in
	// the path priority order the scheduler was built over (index 0 = preferred
	// primary). It returns a negative value when no datagram should be sent this
	// call; the negative value is one of the Pick* sentinels (PickNone for no
	// eligible path, PickPaced for a healthy-but-paced-out shed), so the caller can
	// tell a genuine outage apart from deliberate rate limiting. Pick is safe for
	// concurrent callers on the Bind's send path.
	//
	// class is the frame's traffic class (defect D22): a pacing scheduler exempts
	// ClassControl (WireGuard handshake/keepalive) from the data token buckets so
	// bulk overload cannot shed control frames and starve rekey, while ClassData is
	// fully paced. A non-pacing scheduler (active-backup) ignores class.
	//
	// Pick MAY be stateful: a weighted/aggregating scheduler advances its
	// distribution bookkeeping (deficit/round-robin credits, pacing tokens, offered-
	// load meter) on every call, so ONE Pick consumes ONE frame-selection slot.
	// Callers that only want the liveness-derived active set refreshed — without
	// perturbing distribution — MUST call Recompute, not Pick (see the T40 eager-
	// failover nudge in the multipath Bind).
	Pick(class FrameClass) int

	// Recompute refreshes the scheduler's liveness-derived selection state (which
	// paths are eligible, which is the active primary) from the current PathHealth,
	// and logs any active-path transition, WITHOUT selecting or consuming a frame
	// slot: it advances no distribution/pacing/load state. It is the split-out
	// "recompute the eligible/active set from liveness" half of the old Pick, so the
	// eager-failover nudge (defect D18/T40) can drive an egress-lull failover recompute
	// without stealing a weighted-distribution slot the way a spurious Pick would. For
	// an idempotent scheduler (active-backup) it is exactly Pick without the return;
	// for a stateful one (weighted) it is strictly the non-consuming subset. It is
	// safe for concurrent callers and never calls back into the Bind.
	Recompute()
}

// PathQuality is the per-path measured-quality source the weighted scheduler reads
// to derive distribution weights: the read side of the T13 telemetry Estimate
// (RTT/Jitter/Loss), ANALOGOUS to PathHealth but exposing the quality snapshot
// rather than the up/down verdict. *telemetry.Prober satisfies BOTH PathHealth and
// PathQuality (its Estimate() is mutex-guarded, so it meets the same concurrency
// contract PathHealth documents), which is how one *Prober per path feeds liveness
// AND weight to the scheduler. The weighted scheduler's unit tests drive a synthetic
// PathQuality so the RTT/loss → weight formula is exercised on hand-built Estimates
// with no real probe stream.
type PathQuality interface {
	Estimate() telemetry.Estimate
}

// DynamicScheduler is a Scheduler whose path set can change at runtime (T30): a
// path may be admitted or dropped WITHOUT rebuilding the scheduler or disturbing
// the active selection of the surviving paths. The multipath Bind holds its
// scheduler as a plain Scheduler and type-asserts to this richer interface only
// when a runtime path add/remove is requested, so the Scheduler seam (and the
// T21 weighted policy that will implement it) is preserved: a scheduler that
// does not support dynamic membership simply cannot back a reloadable bind.
//
// The index space is the SAME priority-ordered index Pick returns, and the Bind
// keeps its own path slice index-aligned with this scheduler's path list, so an
// index returned by Pick always addresses the matching path. Both methods are
// safe for concurrent callers.
type DynamicScheduler interface {
	Scheduler
	// AddPath admits h as a NEW lowest-priority path (highest index) and returns
	// that index. Appending at the tail cannot change any existing path's index
	// nor steal the active selection from a higher-priority survivor: an
	// active-backup policy only ever selects the new path once every
	// higher-priority path is down. h must be non-nil.
	AddPath(h PathHealth) (int, error)
	// RemovePath drops the path at index i (shifting higher indices down by one)
	// and repairs the cached selection so a surviving path keeps being selected
	// and, if the dropped path was the active one, egress fails over to the best
	// remaining path on the next Pick. i must be in range.
	RemovePath(i int) error
	// SetPaths replaces the ENTIRE path/health list with health (priority order,
	// index 0 = preferred primary) and clears any cached selection, so the next
	// Pick re-derives the active path from live liveness. The Bind calls it on
	// every Open to re-align the scheduler's membership with the path slice it
	// rebuilds from the current definitions — the single reconciliation point that
	// makes a runtime path add/remove survive a Close→Open cycle index-aligned
	// (T30). It is safe for concurrent callers; health must be non-empty and hold
	// no nil element.
	SetPaths(health []PathHealth) error
}

// PathHealth is the per-path liveness the scheduler consumes: the read side of
// the T13 telemetry liveness state machine, so the scheduler reads exactly the
// up/down verdict T13 already computes (with its own probe-loss hysteresis)
// rather than duplicating detection here.
//
// Concurrency contract: Pick runs on the Bind send path CONCURRENTLY with the
// probe/timer goroutines that mutate liveness, so a production PathHealth MUST
// be INTERNALLY SYNCHRONIZED. *telemetry.Prober satisfies this — its State()
// takes the Prober's mutex (probe.go). A bare *telemetry.Liveness does NOT: it
// is not independently synchronized (probe.go: "must be reached only through
// the Prober") and its State() is an unguarded field read (liveness.go), so
// wiring a live, probe-driven *Liveness directly here is a data race — use a
// *Prober or an explicitly-locked adapter instead. (The sched unit tests drive
// a raw *Liveness on a single goroutine with no concurrent writer, which is not
// a race and is fine for testing.)
type PathHealth interface {
	State() telemetry.PathState
}

// AlwaysUp is a PathHealth that reports StateUp unconditionally. It is the
// composition-root placeholder used until the probe-transport wiring (a
// follow-up task) drives real per-path *telemetry.Prober liveness: with every
// path statically Up, the active-backup scheduler keeps all egress on the
// preferred primary (the data-thrift bring-up behaviour), and swapping in real
// Probers later activates failover with no further Bind or scheduler change.
type AlwaysUp struct{}

// State reports the path as up.
func (AlwaysUp) State() telemetry.PathState { return telemetry.StateUp }

package sched

import (
	"fmt"
	"sync"
	"time"

	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// Config tunes the active-backup scheduler.
type Config struct {
	// FailbackAfter is the failback hysteresis dwell: once a higher-priority
	// path recovers (returns to StateUp) while egress is on a lower-priority
	// backup, the scheduler holds on the backup until the higher-priority path
	// has stayed continuously Up for at least this long before failing egress
	// BACK to it. This is the anti-thrash guard: a primary that flaps up/down
	// never repeatedly steals egress back, because each dip restarts the dwell.
	//
	// Failover in the OTHER direction (active path going Down) is never delayed:
	// the scheduler switches to the best remaining path immediately, since a dead
	// active path cannot carry traffic while a timer runs. The asymmetry — instant
	// failover, debounced failback — is what makes recovery non-thrashing.
	FailbackAfter time.Duration
}

// ActiveBackup is the P1 send-side scheduler: a single ACTIVE path (the
// highest-priority eligible one — index 0, the preferred primary, when it is
// up) carries ALL egress; every other path stays idle (data-thrift by
// construction). It reads per-path liveness from the injected T13 PathHealth
// sources and a clock for the failback dwell, so it is deterministic under test.
//
// Priority is the health-slice order: index 0 is the preferred primary, higher
// indices are progressively-lower-priority backups. A path is eligible when its
// PathHealth reports StateUp.
//
// Concurrency: the send path is concurrent, so Pick recomputes the active path
// under s.mu and every field it touches is guarded by that mutex. It never calls
// back into the Bind, so a Bind holding its own send lock across Pick cannot
// deadlock against it.
type ActiveBackup struct {
	health []PathHealth // index = priority; [0] is the preferred primary
	clock  telemetry.Clock
	cfg    Config
	log    log.Logger

	mu           sync.Mutex
	active       int       // cached selection; -1 == no eligible path
	pending      int       // failback candidate index; -1 == none pending
	pendingSince time.Time // when the current failback candidate first became eligible
}

// compile-time proof ActiveBackup is a (dynamic) Scheduler.
var (
	_ Scheduler        = (*ActiveBackup)(nil)
	_ DynamicScheduler = (*ActiveBackup)(nil)
)

// NewActiveBackup builds the active-backup scheduler over health (priority
// order, index 0 = preferred primary). It fails fast on an empty health set or a
// nil dependency: the scheduler is a required, fully-wired collaborator, not an
// optional one.
func NewActiveBackup(health []PathHealth, cfg Config, clock telemetry.Clock, logger log.Logger) (*ActiveBackup, error) {
	if len(health) == 0 {
		return nil, fmt.Errorf("sched: at least one path health source is required")
	}
	for i, h := range health {
		if h == nil {
			return nil, fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	if clock == nil {
		return nil, fmt.Errorf("sched: clock is required")
	}
	if logger == nil {
		return nil, fmt.Errorf("sched: logger is required")
	}
	return &ActiveBackup{
		health:  health,
		clock:   clock,
		cfg:     cfg,
		log:     logger.Component("sched"),
		active:  -1,
		pending: -1,
	}, nil
}

// AddPath admits h as a new lowest-priority path and returns its index (the new
// tail). Appending at the tail leaves every existing index — including the cached
// active/pending — unchanged, and the new path can only become active once every
// higher-priority path is down, so a runtime admission never disturbs the active
// selection of the surviving paths (T30). It is safe for concurrent callers.
func (s *ActiveBackup) AddPath(h PathHealth) (int, error) {
	if h == nil {
		return 0, fmt.Errorf("sched: cannot add a nil path health source")
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append(s.health, h)
	return len(s.health) - 1, nil
}

// RemovePath drops the health source at index i and repairs the cached selection
// so the surviving paths are undisturbed (T30). The active/pending indices are
// remapped by IDENTITY rather than by arithmetic: the survivor a cached index
// pointed at keeps being pointed at after the slice compaction, and a cached
// index that pointed at the removed path is cleared (-1). Clearing active makes
// the next Pick fail egress over to the best remaining path; clearing pending
// abandons an in-flight failback dwell whose candidate no longer exists. It is
// safe for concurrent callers.
func (s *ActiveBackup) RemovePath(i int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if i < 0 || i >= len(s.health) {
		return fmt.Errorf("sched: remove path index %d out of range [0,%d)", i, len(s.health))
	}
	// Capture the identities the cached indices point at BEFORE compaction, unless
	// they point at the path being removed (then they are cleared).
	var activeH, pendingH PathHealth
	if s.active >= 0 && s.active != i {
		activeH = s.health[s.active]
	}
	if s.pending >= 0 && s.pending != i {
		pendingH = s.health[s.pending]
	}
	s.health = append(s.health[:i], s.health[i+1:]...)
	s.active = indexOfHealth(s.health, activeH)
	s.pending = indexOfHealth(s.health, pendingH)
	if s.pending < 0 {
		s.pendingSince = time.Time{}
	}
	return nil
}

// SetPaths replaces the entire health list with a defensive copy of health and
// clears the cached selection (active/pending), so the next Pick re-derives the
// active path from live liveness. The Bind calls it on every Open to re-align the
// scheduler's membership with the freshly-rebuilt path slice, which is what makes a
// runtime path add/remove survive a Close→Open cycle index-aligned (T30). It fails
// fast on an empty set or a nil element, matching NewActiveBackup's contract. It is
// safe for concurrent callers.
func (s *ActiveBackup) SetPaths(health []PathHealth) error {
	if len(health) == 0 {
		return fmt.Errorf("sched: at least one path health source is required")
	}
	for i, h := range health {
		if h == nil {
			return fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append([]PathHealth(nil), health...)
	s.active = -1
	s.pending = -1
	s.pendingSince = time.Time{}
	return nil
}

// indexOfHealth returns the index of h in hs by identity, or -1 when h is nil or
// absent. Interface equality is pointer identity for the concrete *Prober /
// health values the scheduler holds.
func indexOfHealth(hs []PathHealth, h PathHealth) int {
	if h == nil {
		return -1
	}
	for i := range hs {
		if hs[i] == h {
			return i
		}
	}
	return -1
}

// Pick returns the index of the current active path, recomputing the selection
// against live path health and the clock. It is safe for concurrent callers.
// class is ignored: active-backup has no pacer, so every frame class is treated
// identically (defect D22's control-frame exemption is a pacing concern).
func (s *ActiveBackup) Pick(_ FrameClass) int {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.recomputeLocked(s.clock.Now())
	return s.active
}

// Recompute re-derives the active path from current liveness and the failback
// dwell, exactly as Pick does, but discards the result. Active-backup's selection
// is a single cached index recomputed purely from liveness and the clock, so Pick
// is idempotent and Recompute IS Pick-without-the-return: the eager-failover nudge
// (defect D18/T40) can drive an egress-lull failover recompute through it with no
// behavioural difference from the old Pick-based nudge. It is safe for concurrent
// callers.
func (s *ActiveBackup) Recompute() {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.recomputeLocked(s.clock.Now())
}

// recomputeLocked re-derives the active path from current liveness and the
// failback dwell. Caller holds s.mu.
//
// Selection rule, in priority order:
//   - best = the lowest-index (highest-priority) path currently StateUp.
//   - No path up -> no active path.
//   - Cold start, or the current active is no longer up (best is a
//     lower-priority path) -> switch immediately (instant failover).
//   - best already IS the active -> stable, nothing to do.
//   - best is a HIGHER-priority path than the active (the primary recovered)
//     -> a failback candidate: hold on the current active until best has been
//     continuously up for FailbackAfter, THEN fail back. If the current active
//     itself goes down mid-dwell, move to best at once rather than stall.
func (s *ActiveBackup) recomputeLocked(now time.Time) {
	best := s.bestEligibleLocked()

	if best < 0 {
		s.pending = -1
		s.setActiveLocked(-1, "no eligible path")
		return
	}
	if s.active < 0 || best > s.active {
		// Cold start, or the active path is no longer eligible (best, the first
		// eligible index, sits below it) -> immediate (fail)over.
		s.pending = -1
		s.setActiveLocked(best, "failover")
		return
	}
	if best == s.active {
		s.pending = -1
		return
	}

	// best < s.active: a higher-priority path recovered -> debounced failback.
	if s.pending != best {
		s.pending = best
		s.pendingSince = now
	}
	if now.Sub(s.pendingSince) >= s.cfg.FailbackAfter {
		s.pending = -1
		s.setActiveLocked(best, "failback")
		return
	}
	// Still within the dwell: keep the current active while it stays eligible; if
	// it has gone down, we cannot stall on it — move to best now.
	if s.health[s.active].State() != telemetry.StateUp {
		s.pending = -1
		s.setActiveLocked(best, "failover during failback dwell")
	}
}

// bestEligibleLocked returns the lowest-index path reporting StateUp, or -1.
func (s *ActiveBackup) bestEligibleLocked() int {
	for i := range s.health {
		if s.health[i].State() == telemetry.StateUp {
			return i
		}
	}
	return -1
}

// setActiveLocked stores the active index and logs a transition only when it
// actually changes, so a saturated send path does not log on every Pick.
func (s *ActiveBackup) setActiveLocked(idx int, reason string) {
	if s.active == idx {
		return
	}
	from := s.active
	s.active = idx
	s.log.Info("scheduler active path change",
		"from", from,
		"to", idx,
		"reason", reason,
	)
}

package sched

import (
	"fmt"
	"math"
	"sync"
	"time"

	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/telemetry"
)

// WeightedConfig tunes the weighted-aggregation scheduler. The device builds it
// from config.SchedulerConfig; sched holds its own struct so the package does not
// depend on config. Every field is validated by NewWeighted (fail-fast at the
// composition root), mirroring the config-boundary validation.
type WeightedConfig struct {
	// PerPathCapacity is the reference per-path capacity in frame-selection slots per
	// second: the denominator the aggregation load-gate compares offered load against,
	// and (when Pacing is on) the per-path token-bucket refill rate. There is no
	// measured BDP (P0 §7), so capacity is expressed in the only unit the scheduler
	// observes — Pick() invocations per second. Must be > 0.
	PerPathCapacity float64
	// EngageFraction engages aggregation once smoothed offered load exceeds
	// EngageFraction*PerPathCapacity. In (0,1].
	EngageFraction float64
	// DisengageFraction collapses aggregation to primary-only once smoothed offered
	// load stays below DisengageFraction*PerPathCapacity for CollapseDwell. In
	// [0,EngageFraction): the gap is the hysteresis band that keeps the metered path
	// from dribbling on/off around a single threshold (data-thrift, requirement 2).
	DisengageFraction float64
	// CollapseDwell is the sustained-low-load dwell before collapsing to primary-only
	// (the temporal half of the hysteresis, mirroring the active-backup failback dwell).
	CollapseDwell time.Duration
	// LoadTau is the time constant of the exponentially-weighted offered-load rate
	// estimator. Must be > 0.
	LoadTau time.Duration

	// Pacing turns per-path send-pacing on. When false the token buckets are bypassed
	// (a documented no-op: P0 §7 could not empirically size the pace in the unmetered
	// fixture), but PerPathCapacity still drives the aggregation gate.
	Pacing bool
	// PacingBurst is the per-path token-bucket burst in frame slots. Must be > 0 when
	// Pacing is on.
	PacingBurst float64

	// WeightRTTFloor floors RTT in the weight formula so a cold path (no RTT samples
	// yet, near-zero RTT) cannot be handed unbounded weight. Must be > 0.
	WeightRTTFloor time.Duration
	// WeightLossFloor floors the loss term under the square root so a zero-loss path
	// gets a large-but-finite weight and two zero-loss paths split by inverse-RTT
	// alone. Must be > 0.
	WeightLossFloor float64
}

func (c WeightedConfig) validate() error {
	if c.PerPathCapacity <= 0 {
		return fmt.Errorf("sched: weighted PerPathCapacity must be > 0, got %g", c.PerPathCapacity)
	}
	if c.EngageFraction <= 0 || c.EngageFraction > 1 {
		return fmt.Errorf("sched: weighted EngageFraction must be in (0,1], got %g", c.EngageFraction)
	}
	if c.DisengageFraction < 0 || c.DisengageFraction >= c.EngageFraction {
		return fmt.Errorf("sched: weighted DisengageFraction must be in [0,EngageFraction=%g), got %g", c.EngageFraction, c.DisengageFraction)
	}
	if c.CollapseDwell < 0 {
		return fmt.Errorf("sched: weighted CollapseDwell must be >= 0, got %s", c.CollapseDwell)
	}
	if c.LoadTau <= 0 {
		return fmt.Errorf("sched: weighted LoadTau must be > 0, got %s", c.LoadTau)
	}
	if c.Pacing && c.PacingBurst <= 0 {
		return fmt.Errorf("sched: weighted PacingBurst must be > 0 when pacing is enabled, got %g", c.PacingBurst)
	}
	if c.WeightRTTFloor <= 0 {
		return fmt.Errorf("sched: weighted WeightRTTFloor must be > 0, got %s", c.WeightRTTFloor)
	}
	if c.WeightLossFloor <= 0 {
		return fmt.Errorf("sched: weighted WeightLossFloor must be > 0, got %g", c.WeightLossFloor)
	}
	return nil
}

// FECPolicy is the P3+ forward-error-correction extension seam. Given the path a
// frame was scheduled onto and the current eligible set, it returns ADDITIONAL path
// indices the frame should ALSO egress on for redundancy (e.g. a repair copy on a
// second path). This is a documented hook, NOT an implementation: the current
// single-path Scheduler.Pick returns one index, so wiring redundant transmission
// requires the P3 Bind change that fans a frame out to several sockets. Until then
// a nil policy adds no redundancy and RedundantPaths returns nothing, so the seam is
// inert but present and unit-tested.
type FECPolicy interface {
	RedundantPaths(chosen int, eligible []int) []int
}

// WeightedScheduler is the T21 send-side scheduler: a weighted-aggregation policy
// that, under load, stripes a single flow across every eligible path in proportion
// to a per-path RTT/loss-derived weight, and at low load COLLAPSES to the primary
// (index 0) so the metered backup path stays ~idle (data-thrift, requirement 2). It
// engages the backup only once offered load exceeds one path's capacity and
// disengages with hysteresis (a two-threshold band plus a collapse dwell) so the
// metered path never dribbles on/off. Per-path send-pacing (token buckets) bounds
// each path's egress rate so aggregation does not build a standing queue that
// inflates latency-under-load (P0 §7); pacing is a config no-op when disabled.
//
// It reads per-path liveness from PathHealth (the T13 up/down verdict) and per-path
// quality from PathQuality (the T13 Estimate: RTT/loss). In production BOTH are the
// SAME *telemetry.Prober per path; the unit tests drive synthetic sources.
//
// Weight formula (Mathis-style throughput proxy). A single steady-state TCP flow's
// bandwidth is ∝ 1/(RTT·√p) (Mathis et al.); used here as a RELATIVE path-quality
// proxy it directs more of the aggregate flow onto the path a flow would run faster
// on. Per eligible path:
//
//	w_i = 1 / ( max(RTT_i, RTTFloor) · sqrt(Loss_i + LossFloor) )
//
// normalized over the eligible set. RTTFloor bounds a cold/zero-RTT path; LossFloor
// keeps a zero-loss path finite (two zero-loss paths then split by inverse-RTT
// alone). There is no measured bandwidth to use (Estimate is RTT/Jitter/Loss only,
// P0 §7), so an RTT/loss proxy is the honest choice.
//
// Concurrency mirrors ActiveBackup: every field is guarded by s.mu; the send path
// recomputes under the lock and never calls back into the Bind, so a Bind holding
// its own send lock across Pick cannot deadlock.
//
// Statefulness and the T40 nudge. Pick is STATEFUL — it advances the offered-load
// meter, the aggregation gate, the pacing buckets, and the smooth-weighted-round-
// robin credits, so ONE Pick == ONE frame. The eager-failover nudge (defect D18)
// must therefore NOT call Pick (it would steal a distribution slot and skew the
// weights); it calls Recompute, which refreshes only the liveness-derived eligible/
// active set and logs any active-path transition, touching NONE of that per-frame
// distribution state.
type WeightedScheduler struct {
	health  []PathHealth  // index = priority; [0] is the preferred primary
	quality []PathQuality // parallel to health; element may be nil (neutral weight)
	clock   telemetry.Clock
	cfg     WeightedConfig
	log     log.Logger
	fec     FECPolicy // P3+ redundancy seam; nil = no FEC

	mu sync.Mutex

	// Offered-load meter: an exponentially-weighted event-rate estimator (each Pick is
	// one event; the estimate converges to the offered Pick rate in events/sec).
	loadRate float64
	haveLoad bool
	lastLoad time.Time

	// Aggregation gate (hysteresis).
	aggregating bool
	belowSince  time.Time // when load first fell below the disengage threshold; zero == not pending

	// Smooth-weighted-round-robin credits, parallel to health (global path index).
	current []float64

	// Per-path pacing token buckets, parallel to health.
	tokens   []float64
	lastFill time.Time
	haveFill bool

	// Active-primary cache: the best eligible path, for eager-failover transition
	// logging (parity with ActiveBackup). -1 == none.
	active int

	// Pacer-shedding log rate limiter: under sustained overload shedding is per-frame
	// (thousands/s), so the "pacer shedding" diagnostic is coalesced to at most one
	// record per shedLogInterval, carrying the count shed since the last record.
	shedCount   int
	lastShedLog time.Time
}

// shedLogInterval bounds how often the pacer-shedding diagnostic is emitted, so a
// sustained overload logs a periodic coalesced record rather than one line per
// dropped frame.
const shedLogInterval = 1 * time.Second

// compile-time proof WeightedScheduler is a (dynamic) Scheduler.
var (
	_ Scheduler        = (*WeightedScheduler)(nil)
	_ DynamicScheduler = (*WeightedScheduler)(nil)
)

// NewWeighted builds the weighted-aggregation scheduler over parallel health and
// quality slices in priority order (index 0 = preferred primary). health and quality
// must be the same length; a quality element MAY be nil (that path then gets a
// neutral weight until a real PathQuality is wired). It fails fast on an empty or
// length-mismatched set, a nil health element, a nil dependency, or an invalid config.
func NewWeighted(health []PathHealth, quality []PathQuality, cfg WeightedConfig, clock telemetry.Clock, logger log.Logger) (*WeightedScheduler, error) {
	if len(health) == 0 {
		return nil, fmt.Errorf("sched: at least one path health source is required")
	}
	if len(quality) != len(health) {
		return nil, fmt.Errorf("sched: quality set (%d) must be one entry per health source (%d)", len(quality), len(health))
	}
	for i, h := range health {
		if h == nil {
			return nil, fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	if clock == nil {
		return nil, fmt.Errorf("sched: clock is required")
	}
	if logger == nil {
		return nil, fmt.Errorf("sched: logger is required")
	}
	if err := cfg.validate(); err != nil {
		return nil, err
	}
	return &WeightedScheduler{
		health:  append([]PathHealth(nil), health...),
		quality: append([]PathQuality(nil), quality...),
		clock:   clock,
		cfg:     cfg,
		log:     logger.Component("sched"),
		current: make([]float64, len(health)),
		tokens:  fullBuckets(len(health), cfg.PacingBurst),
		active:  -1,
	}, nil
}

// SetFEC installs the P3+ redundancy policy (nil clears it). It is the documented
// extension point for FEC-aware path selection; the current single-path Pick does
// not consult it (redundant transmission needs the P3 Bind fan-out), but
// RedundantPaths exposes it so a P3 Bind can query the additional paths per frame.
func (s *WeightedScheduler) SetFEC(fec FECPolicy) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.fec = fec
}

// RedundantPaths reports the ADDITIONAL path indices a frame scheduled onto chosen
// should also egress on, per the installed FECPolicy over the current eligible set.
// It returns nil when no policy is installed (no FEC). It is the P3 hook a redundant-
// transmission Bind would call alongside Pick; today it is a documented, unit-tested
// seam with no in-tree caller on the hot path.
func (s *WeightedScheduler) RedundantPaths(chosen int) []int {
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.fec == nil {
		return nil
	}
	return s.fec.RedundantPaths(chosen, s.eligibleLocked())
}

// Pick selects the path for the NEXT frame and advances all per-frame distribution
// state (offered-load meter, aggregation gate, pacing buckets, round-robin credits).
// It returns a negative value when no path is eligible OR when every eligible path
// is paced out (the frame is dropped rather than queued — pacing bounds egress and,
// by dropping the overflow, bounds the send backlog). It is safe for concurrent
// callers.
func (s *WeightedScheduler) Pick(class FrameClass) int {
	now := s.clock.Now()
	s.mu.Lock()
	defer s.mu.Unlock()

	// Capture the inter-sample idle gap BEFORE observeLoadLocked advances lastLoad: a
	// long gap since the previous offered frame is itself the strongest evidence of low
	// load, and the collapse hysteresis must count it (criticism #1 — otherwise an
	// abrupt overload stop leaves the gate engaged across the whole idle span and the
	// next low burst dribbles onto the metered path).
	gap := s.loadGapLocked(now)
	s.recomputeLocked(now)       // liveness refresh + eager-failover log
	s.observeLoadLocked(now)     // this Pick is one offered frame (decays across the gap)
	s.updateGateLocked(now, gap) // engage/disengage aggregation (hysteresis, idle-aware)
	s.refillLocked(now)          // top up pacing buckets

	eligible := s.eligibleLocked()
	if len(eligible) == 0 {
		return PickNone
	}
	if !s.aggregating {
		// Data-thrift: at low load only the primary (best eligible) carries traffic;
		// the metered backup stays idle. A path-down excludes it from eligible, so
		// eligible[0] is the surviving highest-priority path — failover is preserved.
		return s.serveLocked(now, eligible[0], class)
	}
	weights := s.weightsLocked(eligible)
	return s.selectAggregatingLocked(now, eligible, weights, class)
}

// loadGapLocked returns the wall-clock gap since the previous offered-load sample, or
// 0 before the first sample. Caller holds s.mu.
func (s *WeightedScheduler) loadGapLocked(now time.Time) time.Duration {
	if !s.haveLoad {
		return 0
	}
	gap := now.Sub(s.lastLoad)
	if gap < 0 {
		gap = 0
	}
	return gap
}

// Recompute refreshes only the liveness-derived eligible/active set from the current
// PathHealth and logs any active-path transition. It advances NONE of the per-frame
// distribution state (load meter, gate, pacing, round-robin credits), so the eager-
// failover nudge (defect D18/T40) drives an egress-lull failover recompute through it
// WITHOUT stealing a weighted-distribution slot the way a spurious Pick would. It is
// safe for concurrent callers.
func (s *WeightedScheduler) Recompute() {
	now := s.clock.Now()
	s.mu.Lock()
	defer s.mu.Unlock()
	s.recomputeLocked(now)
}

// recomputeLocked refreshes the active-primary cache (best eligible path) and logs a
// transition on change. Caller holds s.mu.
func (s *WeightedScheduler) recomputeLocked(_ time.Time) {
	best := s.bestEligibleLocked()
	s.setActiveLocked(best)
}

// serveLocked applies pacing to a single chosen path: it returns idx when the frame
// is admitted, or PickPaced when pacing is on and the path has no token (the frame is
// shed — dropped, bounding egress and backlog — and the shedding diagnostic is
// rate-limited). A ClassControl frame is pacing-EXEMPT (defect D22): it egresses on
// idx unconditionally, spending no token and never shed, so bulk overload cannot
// starve WireGuard rekey. Caller holds s.mu.
func (s *WeightedScheduler) serveLocked(now time.Time, idx int, class FrameClass) int {
	if class == ClassControl {
		return idx
	}
	if s.tryConsumeLocked(idx) {
		return idx
	}
	return s.shedLocked(now)
}

// selectAggregatingLocked picks a path proportional to weight (smooth weighted round
// robin) and applies pacing. When the round-robin's ideal pick is paced out it falls
// through to any other eligible path that still has a token, so aggregate egress is
// bounded by the SUM of the per-path paces; when every eligible path is paced out it
// sheds the frame (PickPaced). A ClassControl frame is pacing-EXEMPT (defect D22): it
// egresses on the weight-ideal path spending no token and is never shed, so bulk
// overload across every path cannot starve WireGuard rekey. Caller holds s.mu.
func (s *WeightedScheduler) selectAggregatingLocked(now time.Time, eligible []int, weights []float64, class FrameClass) int {
	ideal := s.swrrPickLocked(eligible, weights)
	if class == ClassControl {
		return ideal
	}
	if s.tryConsumeLocked(ideal) {
		return ideal
	}
	for _, gi := range eligible {
		if gi == ideal {
			continue
		}
		if s.tryConsumeLocked(gi) {
			return gi
		}
	}
	return s.shedLocked(now)
}

// shedLocked records one paced-out (shed) frame and emits the coalesced "pacer
// shedding" diagnostic at most once per shedLogInterval. It returns PickPaced so the
// Send path can map the drop to a distinct, non-outage error/log (criticism #3): the
// paths are healthy, this is deliberate rate limiting. Caller holds s.mu.
func (s *WeightedScheduler) shedLocked(now time.Time) int {
	s.shedCount++
	if s.lastShedLog.IsZero() || now.Sub(s.lastShedLog) >= shedLogInterval {
		s.log.Info("scheduler pacer shedding",
			"shed_frames", s.shedCount,
			"load_fps", s.loadRate,
		)
		s.lastShedLog = now
		s.shedCount = 0
	}
	return PickPaced
}

// swrrPickLocked is nginx's smooth weighted round-robin over the eligible set: it
// advances each eligible path's credit by its weight, picks the max-credit path, and
// subtracts the total weight from the winner. Over many calls the selection frequency
// of each path converges to its weight share, interleaved smoothly rather than
// bursted. Caller holds s.mu; weights is aligned to eligible order.
func (s *WeightedScheduler) swrrPickLocked(eligible []int, weights []float64) int {
	var total float64
	for _, w := range weights {
		total += w
	}
	best := -1
	var bestCur float64
	for k, gi := range eligible {
		s.current[gi] += weights[k]
		if best < 0 || s.current[gi] > bestCur {
			best = gi
			bestCur = s.current[gi]
		}
	}
	s.current[best] -= total
	return best
}

// weightsLocked computes the normalized Mathis-style weight for each eligible path
// from its PathQuality Estimate (RTT/loss). A path with NO usable quality — a nil
// quality source, or an all-zero Estimate (RTT==0: no probe sample yet) — is treated
// as genuinely NEUTRAL: it receives the MEAN of the measured paths' weights, so an
// unwired/cold path splits evenly rather than dominating. This matters because the
// floors would otherwise hand an all-zero Estimate the MAXIMUM weight (RTT floored to
// WeightRTTFloor, zero loss), letting a health-only path admitted via AddPath siphon
// the dominant share — the opposite of neutral. When every eligible path is neutral,
// all get equal weight. Caller holds s.mu; the result is aligned to eligible order and
// sums to 1.
func (s *WeightedScheduler) weightsLocked(eligible []int) []float64 {
	w := make([]float64, len(eligible))
	measured := make([]bool, len(eligible))
	rttFloor := float64(s.cfg.WeightRTTFloor)
	var sumMeasured float64
	nMeasured := 0
	for k, gi := range eligible {
		q := s.quality[gi]
		if q == nil {
			continue // unwired: neutral, filled below
		}
		est := q.Estimate()
		if est.RTT <= 0 {
			continue // no RTT sample yet (cold estimator): neutral, filled below
		}
		rtt := float64(est.RTT)
		if rtt < rttFloor {
			rtt = rttFloor
		}
		loss := est.Loss
		if loss < 0 {
			loss = 0
		}
		wi := 1.0 / (rtt * math.Sqrt(loss+s.cfg.WeightLossFloor))
		w[k] = wi
		measured[k] = true
		sumMeasured += wi
		nMeasured++
	}
	// Neutral weight: the mean of the measured weights (so a neutral path splits evenly
	// with the measured set, never outweighing it); equal weights when nothing measured.
	neutral := 1.0
	if nMeasured > 0 {
		neutral = sumMeasured / float64(nMeasured)
	}
	var sum float64
	for k := range w {
		if !measured[k] {
			w[k] = neutral
		}
		sum += w[k]
	}
	if sum <= 0 {
		for k := range w {
			w[k] = 1.0 / float64(len(w))
		}
		return w
	}
	for k := range w {
		w[k] /= sum
	}
	return w
}

// observeLoadLocked folds one offered frame into the exponentially-weighted event-
// rate estimator. Each event adds 1/tau (per-second units) after decaying the prior
// estimate by exp(-dt/tau); the steady-state estimate converges to the offered rate
// in events/sec. It is robust to dt==0 (many Picks at one clock instant just add
// without decay). Caller holds s.mu.
func (s *WeightedScheduler) observeLoadLocked(now time.Time) {
	tau := s.cfg.LoadTau.Seconds()
	if !s.haveLoad {
		s.haveLoad = true
		s.lastLoad = now
		s.loadRate = 0
	} else {
		dt := now.Sub(s.lastLoad).Seconds()
		if dt < 0 {
			dt = 0
		}
		s.loadRate *= math.Exp(-dt / tau)
		s.lastLoad = now
	}
	s.loadRate += 1.0 / tau
}

// updateGateLocked engages or disengages aggregation from the smoothed offered load,
// with hysteresis: engage the instant load exceeds EngageFraction*capacity; collapse
// back to primary-only only after load stays below DisengageFraction*capacity for
// CollapseDwell. The two-threshold band plus the dwell keep the metered path from
// flapping on/off around a single point (requirement 2). gap is the wall-clock idle
// span since the previous offered frame.
//
// Idle time IS low load (criticism #1). The gate only advances on a Pick, so an
// overload that stops ABRUPTLY (load still above disengage on the last frame) would
// otherwise stay engaged across an arbitrarily long idle span and stripe the first
// ~CollapseDwell of the NEXT low burst onto the metered backup — a data-thrift leak.
// Two provisions close it: (a) an idle gap that alone reaches CollapseDwell forces an
// immediate collapse, since a gap that long is itself proof of sustained low load; and
// (b) belowSince is BACKDATED to when load actually dropped (the previous sample,
// now-gap) rather than seeded at this post-idle frame, so the dwell counts the idle.
// The load EWMA decays across gap in observeLoadLocked, so a post-idle frame reads
// ~0 and the collapse fires on the FIRST frame of the next burst. Caller holds s.mu.
func (s *WeightedScheduler) updateGateLocked(now time.Time, gap time.Duration) {
	engage := s.cfg.EngageFraction * s.cfg.PerPathCapacity
	disengage := s.cfg.DisengageFraction * s.cfg.PerPathCapacity
	if !s.aggregating {
		if s.loadRate > engage {
			s.aggregating = true
			s.belowSince = time.Time{}
			s.log.Info("scheduler aggregation change", "to", "aggregating", "load_fps", s.loadRate)
		}
		return
	}
	// (a) A single idle gap of at least the dwell is conclusive: collapse now.
	if gap >= s.cfg.CollapseDwell {
		s.aggregating = false
		s.belowSince = time.Time{}
		s.log.Info("scheduler aggregation change", "to", "collapsed", "reason", "idle gap", "gap", gap.String())
		return
	}
	if s.loadRate < disengage {
		if s.belowSince.IsZero() {
			// (b) Backdate to when load dropped: the previous sample (now-gap), not this
			// post-idle frame, so the idle span counts toward the dwell.
			s.belowSince = now.Add(-gap)
		}
		if now.Sub(s.belowSince) >= s.cfg.CollapseDwell {
			s.aggregating = false
			s.belowSince = time.Time{}
			s.log.Info("scheduler aggregation change", "to", "collapsed", "reason", "sustained low load", "load_fps", s.loadRate)
		}
		return
	}
	// Load rose back above the disengage threshold: reset the collapse dwell.
	s.belowSince = time.Time{}
}

// refillLocked tops up every per-path token bucket by PerPathCapacity·elapsed, capped
// at PacingBurst. The first call seeds every bucket full. It is a no-op accountant
// when pacing is disabled (tryConsumeLocked always admits), but the buckets are still
// maintained so toggling pacing needs no re-seed. Caller holds s.mu.
func (s *WeightedScheduler) refillLocked(now time.Time) {
	if !s.haveFill {
		s.haveFill = true
		s.lastFill = now
		for i := range s.tokens {
			s.tokens[i] = s.cfg.PacingBurst
		}
		return
	}
	dt := now.Sub(s.lastFill).Seconds()
	if dt < 0 {
		dt = 0
	}
	add := s.cfg.PerPathCapacity * dt
	for i := range s.tokens {
		s.tokens[i] += add
		if s.tokens[i] > s.cfg.PacingBurst {
			s.tokens[i] = s.cfg.PacingBurst
		}
	}
	s.lastFill = now
}

// tryConsumeLocked spends one token from path idx's bucket, reporting whether the
// frame is admitted. With pacing disabled it always admits (the buckets are inert).
// Caller holds s.mu.
func (s *WeightedScheduler) tryConsumeLocked(idx int) bool {
	if !s.cfg.Pacing {
		return true
	}
	if s.tokens[idx] >= 1 {
		s.tokens[idx]--
		return true
	}
	return false
}

// eligibleLocked returns the global indices of paths reporting StateUp, in priority
// order. Caller holds s.mu.
func (s *WeightedScheduler) eligibleLocked() []int {
	e := make([]int, 0, len(s.health))
	for i := range s.health {
		if s.health[i].State() == telemetry.StateUp {
			e = append(e, i)
		}
	}
	return e
}

// bestEligibleLocked returns the lowest-index path reporting StateUp, or -1.
func (s *WeightedScheduler) bestEligibleLocked() int {
	for i := range s.health {
		if s.health[i].State() == telemetry.StateUp {
			return i
		}
	}
	return -1
}

// setActiveLocked stores the active-primary index and logs a transition only when it
// changes, so a saturated send path does not log on every Pick. The message matches
// ActiveBackup's ("scheduler active path change") so downstream log parsing (the e2e
// failover harness) reads either policy identically.
func (s *WeightedScheduler) setActiveLocked(idx int) {
	if s.active == idx {
		return
	}
	from := s.active
	s.active = idx
	s.log.Info("scheduler active path change", "from", from, "to", idx, "reason", "weighted recompute")
}

// AddPath admits h as a new lowest-priority path and returns its index (the new
// tail). Its quality source is h itself when h also satisfies PathQuality (the
// production *Prober does); a health-ONLY source (no PathQuality) is recorded with a
// nil quality and weightsLocked then gives it the NEUTRAL (mean) weight, so it splits
// evenly and never siphons the dominant share. Appending at the tail leaves every
// existing index unchanged and the new path only carries traffic once aggregation
// engages, so a runtime admission never disturbs the surviving paths' distribution
// (T30). It is safe for concurrent callers.
func (s *WeightedScheduler) AddPath(h PathHealth) (int, error) {
	if h == nil {
		return 0, fmt.Errorf("sched: cannot add a nil path health source")
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append(s.health, h)
	s.quality = append(s.quality, asQuality(h))
	s.current = append(s.current, 0)
	s.tokens = append(s.tokens, s.cfg.PacingBurst)
	return len(s.health) - 1, nil
}

// RemovePath drops the path at index i (shifting higher indices down by one) and
// clears the cached active selection so the next Pick/Recompute re-derives it from
// live liveness. The round-robin credits are positional and compacted with the path
// list; a brief re-warm of the smoothing after a membership change is harmless. It is
// safe for concurrent callers.
func (s *WeightedScheduler) RemovePath(i int) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if i < 0 || i >= len(s.health) {
		return fmt.Errorf("sched: remove path index %d out of range [0,%d)", i, len(s.health))
	}
	s.health = append(s.health[:i], s.health[i+1:]...)
	s.quality = append(s.quality[:i], s.quality[i+1:]...)
	s.current = append(s.current[:i], s.current[i+1:]...)
	s.tokens = append(s.tokens[:i], s.tokens[i+1:]...)
	s.active = -1
	return nil
}

// SetPaths replaces the entire health list (priority order, index 0 = preferred
// primary), rebuilding the parallel quality slice from the new sources, resetting the
// round-robin credits and pacing buckets, and collapsing aggregation to primary-only
// so the next Pick re-derives everything from live liveness. The Bind calls it on
// every Open to re-align the scheduler with the freshly-rebuilt path slice (T30). It
// fails fast on an empty set or a nil element, matching NewWeighted. It is safe for
// concurrent callers.
func (s *WeightedScheduler) SetPaths(health []PathHealth) error {
	if len(health) == 0 {
		return fmt.Errorf("sched: at least one path health source is required")
	}
	for i, h := range health {
		if h == nil {
			return fmt.Errorf("sched: path %d health source is nil", i)
		}
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	s.health = append([]PathHealth(nil), health...)
	s.quality = make([]PathQuality, len(health))
	for i, h := range health {
		s.quality[i] = asQuality(h)
	}
	s.current = make([]float64, len(health))
	s.tokens = fullBuckets(len(health), s.cfg.PacingBurst)
	s.haveFill = false
	s.aggregating = false
	s.belowSince = time.Time{}
	s.active = -1
	return nil
}

// asQuality returns h as a PathQuality when it also implements that interface (the
// production *telemetry.Prober does — one source drives both liveness and weight), or
// nil so the path gets a neutral weight.
func asQuality(h PathHealth) PathQuality {
	if q, ok := h.(PathQuality); ok {
		return q
	}
	return nil
}

// fullBuckets returns n token buckets each seeded to burst.
func fullBuckets(n int, burst float64) []float64 {
	t := make([]float64, n)
	for i := range t {
		t[i] = burst
	}
	return t
}

package bind

import (
	"crypto/rand"
	"errors"
	"fmt"
	"net"
	"net/netip"
	"sync"
	"sync/atomic"
	"syscall"
	"time"

	"github.com/amnezia-vpn/amneziawg-go/conn"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
	"github.com/7mind/wanbond/internal/reseq"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// socketRecvBuffer is the SO_RCVBUF requested on every per-path socket, matching
// wireguard-go's StdNetBind (~7 MiB). A large receive buffer absorbs the bursts a
// bonded, reordered flow delivers while the userspace engine catches up; the
// pass-through P0 Bind used the OS default and lost datagrams under load (P0
// findings §1/§2). The kernel silently caps the request at net.core.rmem_max, so
// the effective size may be smaller on an untuned host — best-effort by design.
const socketRecvBuffer = 7 << 20

// multipathBatchSize is the number of datagrams a ReceiveFunc / Send handles per
// call. T12 keeps it at 1 (one syscall per datagram, per path); GSO/GRO batching
// is best-effort future work (P0 findings §2) tracked separately and does not
// change the wire format.
const multipathBatchSize = 1

// maxDatagram bounds a single received outer datagram. It comfortably exceeds a
// full-MTU inner packet plus every outer/WG/amnezia-junk overhead.
const maxDatagram = 65535

// Receive-resequencer tuning (T18), sized against P0 findings §6.
//
// resequencerWindow is the maximum span of outer-seq positions the receive
// resequencer buffers while it waits for an out-of-order frame. WG's inner RFC
// 6479 anti-replay window is 8128 messages (docs/p0-findings.md §6); the window
// here sits ~4x below that, so even a worst-case burst of reordered/held frames
// stays comfortably inside the inner filter's tolerance while spanning far more
// packets than the measured ~19 ms emulated cross-path skew (and the larger,
// more variable real Starlink/5G skew) needs at realistic per-path rates.
//
// resequencerTimeout bounds how long a head-of-line-blocked run is held for a
// missing (presumed-lost) lower frame before that gap is skipped and the run
// released. It caps the added latency — and the stall a slow/lossy path can
// impose on the whole bond (P0 §7 head-of-line concern) — to a few multiples of
// a Starlink RTT (~45 ms) rather than holding a gap forever.
const (
	resequencerWindow  = 2048
	resequencerTimeout = 250 * time.Millisecond
)

// defaultMaxDemuxSources caps the source->peer demux map (peerBySource), the
// PROVISIONAL/unbound-source tracking state whose growth an attacker probes at
// bootstrap (Q26/Q27). It is sized SEPARATELY from the steady-state peer set
// (m.peersByName, bounded by the static configured [[wireguard.peers]]): a source
// AddrPort enters this map only on an authenticated PROBE (T88). The map is keyed by
// the full source netip.AddrPort (address+port, D47) — NOT the bare address — so two
// peers behind ONE public IP (CGNAT) bind to distinct entries and demux independently.
//
// This GLOBAL cap is the outer bound; within it a PER-PEER quota (maxDemuxSources /
// len(peers), floor 1, D49) is enforced so one party holding ONE valid psk that floods
// spoofed sources to its OWN peer exhausts only ITS OWN quota and never starves another
// peer's bootstrap PROBE (Q27(1) cross-peer isolation). Two eviction/drop regimes apply
// to a NEW source AddrPort:
//   - SAME-peer (roam port-churn): a peer already at its per-peer quota that authenticates
//     a NEW AddrPort for ITSELF evicts its OWN oldest binding (LRU within the peer) to admit
//     it — a live roaming peer is NEVER dropped and its footprint never grows past quota, so
//     it can never evict ANOTHER peer's slot (never-evict-live w.r.t. others holds).
//   - CROSS-peer (drop-on-exhaustion): a peer BELOW its quota whose NEW source would grow the
//     map past the GLOBAL cap is refused — it may not steal another peer's headroom. Bootstrap
//     degrades; WG retransmits re-drive it once a slot frees.
//
// An already-bound (live) source is NEVER evicted by another peer. Roam/re-affirm of an
// already-present AddrPort (T90) does not grow the map, so it is never blocked by the cap. A
// dead peer's bindings are reclaimed on teardown (TearDownPeer), freeing slots. The default is
// generous relative to any realistic concentrator's peer×roam-churn count yet bounds the flood
// surface.
const defaultMaxDemuxSources = 1024

var (
	// ErrNoHealthyPath is exported (I4) so the device-package engineLogger adapter can
	// errors.Is-match it against the engine's wrapped Errorf args to gate the startup
	// no-healthy-path warmup coalescing without string-matching the log message.
	ErrNoHealthyPath = errors.New("bind: no healthy path with a known remote endpoint")
	// errPacerShedding is returned by Send when the scheduler shed the datagram for
	// pacing (PickPaced) while paths are healthy — deliberate rate limiting, NOT an
	// outage. It is DISTINCT from ErrNoHealthyPath so operator logs and the e2e
	// log-grep harness can tell shedding from total path failure (the drop behavior is
	// identical to the pre-existing no-path case; only the diagnostic differs). The
	// coalesced, rate-limited "pacer shedding" record is emitted by the scheduler.
	errPacerShedding = errors.New("bind: datagram shed by send pacer (paths healthy, rate limited)")
	errClosed        = net.ErrClosed
)

// sharedPathState is the per-SOCKET state of one configured uplink, SHARED across
// every peer bound beneath the Bind: its stable path-id, source address, and the
// source-bound UDP socket (drained by exactly one Bind-owned readLoop). A concentrator
// front-ends many peers on the SAME socket, so this identity is owned once per socket
// and referenced by every peer's per-(peer,path) view (peerPathState). On the single-peer
// edge/hub there is exactly one peer, so each shared path has exactly one peerPathState.
// The deferred-path machinery (deferredPath, m.deferred) likewise operates on this shared
// socket layer — a runtime add/remove of a shared path fans the per-(peer,path) state out
// to every bound peer (see attachSharedPathLocked / RemovePath).
type sharedPathState struct {
	name string
	id   uint8
	src  netip.Addr
	conn *net.UDPConn

	// views is the per-peer VIEW set of THIS shared socket — one peerPathState per bound
	// peer — published copy-on-write through an atomic.Pointer so the single Bind-owned
	// readLoop demuxes an inbound datagram to its owning peer's view WITHOUT m.mu on the
	// receive hot path (the same lock-free-publish discipline peersView/resequencer use).
	// It is (re)published under m.mu at every fan-out site (Open / attachPeerPathLocked /
	// deferred promote, and each concentrator peer bind). On the single-peer edge/hub it
	// holds exactly one entry (the primary's view), which handleInbound reads as "no demux
	// needed" — the byte-identical fast path. len(views)>1 marks a shared concentrator
	// socket whose datagrams must be source-demuxed to the owning peer (T88).
	views atomic.Pointer[[]*peerPathState]
}

// addViewLocked publishes pp as a per-peer view of this shared socket for the lock-free
// receive demux (T88). Copy-on-write: it republishes a NEW slice with pp appended, so a
// readLoop mid-iteration over the previously-published snapshot is never disturbed. The
// caller holds m.mu (every fan-out site does), which serializes writers; readers Load
// without a lock.
func (sp *sharedPathState) addViewLocked(pp *peerPathState) {
	old := sp.views.Load()
	var next []*peerPathState
	if old != nil {
		next = make([]*peerPathState, len(*old), len(*old)+1)
		copy(next, *old)
	}
	next = append(next, pp)
	sp.views.Store(&next)
}

// peerPathState is one peer's per-(peer,path) VIEW of a shared uplink: that peer's own
// decode Codec (each path receives on its own goroutine, so the Codec's scratch is never
// shared), the peer's own learned/configured return remote, the peer's own probe
// initiator for this path, and the peer's own per-path OUTER-wire byte counters. The
// remote is either configured (edge dest_addr / peer endpoint) or LEARNED from inbound
// traffic (concentrator) — but it lives strictly BELOW the engine's single virtual
// endpoint, so the engine never sees this per-(peer,path) bookkeeping churn.
//
// It EMBEDS its *sharedPathState so the socket identity (name/id/src/conn) is reached
// transparently, and back-references the owning peerState so a receive handler resolves
// exactly that peer's resequencer/reflector/FEC decoder.
type peerPathState struct {
	*sharedPathState
	peer  *peerState
	codec *frame.Codec
	// prober is this (peer,path)'s own probe initiator (nil when the bind runs without the
	// probe transport). It is set at path creation and immutable for the path's life,
	// so the Bind-owned receive goroutine reaches it via the peerPathState it already
	// holds — NOT through a shared, dynamically-mutated probers slice — which is
	// what keeps echo handling race-free while paths are added/removed at runtime (T30).
	prober *telemetry.Prober

	// txBytes/rxBytes are cumulative OUTER-wire byte counters for this (peer,path), the
	// per-path traffic accounting the /metrics exposition reports (T23). Both are
	// TRUE-WIRE-VOLUME counters: txBytes counts every outer datagram this path actually
	// writes to its socket — DATA/PARITY on the Send hot path (T23/T24), PROBE frames
	// emitted by emitProbes, and PROBE echoes reflected back by dispatchInbound — each
	// counted only once the write returns a nil error; rxBytes counts every outer
	// datagram this path's readLoop receives (DATA, PROBE, and echo alike). Neither
	// counter is DATA-only or Send-only (D48): a healthy idle standby path still emits
	// and echoes probes, so its txBytes keeps advancing even while active-backup
	// collapses all DATA onto the primary. They are atomics so the send/receive/probe
	// hot paths increment them WITHOUT taking m.mu (lock-free) from whichever goroutine
	// performs the write (Send's caller, the probe-loop goroutine, or this path's
	// readLoop), and the scrape/snapshot path reads them with a plain atomic Load.
	txBytes atomic.Uint64
	rxBytes atomic.Uint64

	mu        sync.Mutex
	remote    netip.AddrPort
	hasRemote bool
}

// peerState holds the per-PEER datapath state that was a process-global singleton before
// the multi-peer concentrator split: the SINGLE virtual endpoint the engine holds for this
// peer, the peer's send scheduler, its own outer-seq space, its shared send Codec, its
// probe reflector, its receive resequencer and FEC send/receive planes, its per-path probe
// initiators, and its per-(peer,path) views over the shared sockets. The single-peer
// edge/hub constructs EXACTLY ONE peerState (so behaviour is byte-identical to the pre-split
// singleton — Multipath embeds it as the primary and the datapath reaches its fields through
// that embed); the concentrator constructs one peerState per bound peer. resequencer and
// fecRecv stay atomic.Pointer, and outerSeq atomic, so the lock-free receive/send fast paths
// read them WITHOUT m.mu.
type peerState struct {
	// name is the peer id/name, the key under which Multipath.peersByName holds this peer.
	// Empty on the single-peer edge/hub (there is only one peer to key).
	name string

	// psk is THIS peer's effective pre-shared key: the sole seam from which every frame
	// Codec this peer derives (its sendCodec and each per-(peer,path) receive codec, via
	// newCodec) and its probe Reflector authenticate. The single-peer edge/hub sets it to
	// the one configured psk (so behaviour is byte-identical to the pre-split singleton);
	// the concentrator sets a DIFFERENT psk per bound peer, so one peer's codec/reflector
	// rejects another peer's frames (T84). NewCodec/NewReflector PSK-derivation itself is
	// unchanged — only WHICH psk each peer feeds them differs.
	psk config.Key

	// Immutable per-peer collaborators, built at construction and persisting across the
	// Open→Close socket lifecycle (the concentrator pins virt's destination once for the
	// process life, so virt in particular must NOT be recreated per Open).
	virt      *udpEndpoint
	scheduler sched.Scheduler
	reflector *telemetry.Reflector
	// newProber mints a prober for a path admitted to THIS peer at runtime (T30); nil
	// disables runtime path addition for the peer (a bind without the probe transport).
	newProber ProberFactory
	// probers is this peer's BOOT-TIME per-path probe initiator set, in durable-membership
	// (m.defs) order — bound AND deferred — shared with this peer's scheduler. At Open each
	// bound entry is bound onto its peerPathState (pp.prober), and thereafter the hot paths
	// reach a path's prober through the peerPathState — never by indexing this slice — so a
	// runtime path add/remove cannot race echo handling. Nil when the peer runs without the
	// probe transport; a nil here also gates the whole probe loop off.
	probers []*telemetry.Prober

	// Per-Open state, (re)built by Open and cleared by Close.
	sendCodec *frame.Codec
	paths     []*peerPathState
	outerSeq  atomic.Uint64
	// resequencer is this peer's shared T18 receive resequencing buffer. Published
	// atomically so the per-path readLoop goroutines read it WITHOUT m.mu.
	resequencer atomic.Pointer[reseq.Resequencer]
	// FEC datapath (T24), per peer. Both published atomically like resequencer so the
	// lock-free receive fast path Loads fecRecv, and the lazy re-instantiation on re-bind
	// (ensurePeerReceiveInstantiated, on a readLoop that must not take m.mu) can Store
	// fecSend without racing Send's under-m.mu Load. The ENCODER inside fecSend is still
	// mutated (Admit/Tick) only under m.mu — the atomic pointer governs publication of the
	// fecSender object, not its encoder's single-writer discipline. Both nil when FEC is off.
	fecSend atomic.Pointer[fecSender]
	fecRecv atomic.Pointer[fecReceiver]

	// lifecycleMu serializes lazy (re)instantiation of the heavy trio (resequencer, fecRecv,
	// fecSend) on a readLoop goroutine (ensurePeerReceiveInstantiated) against teardown's
	// clearing of that trio (teardownPeerLocked), so a teardown interleaving mid-instantiation
	// can never leave a half-published plane (a fecRecv/fecSend without its resequencer) nor
	// resurrect a plane on a torn-down peer that the next re-bind then reuses stale. It is a
	// LEAF lock taken either ALONE (instantiation — which must never take m.mu, so Close's
	// readersWG.Wait under m.mu cannot deadlock on it) or UNDER m.mu (teardown), giving the
	// single fixed order m.mu -> lifecycleMu and no cycle (instantiation never reaches for m.mu).
	lifecycleMu sync.Mutex
}

// newPeerState builds the durable per-peer datapath state whose probe Reflector — and,
// through ps.psk, every frame Codec this peer later derives in Open/AddPath (its sendCodec
// and each per-(peer,path) receive codec, via newCodec) — authenticate under THIS peer's
// psk. It is the seam that replaces the pre-split single-psk assumption (T84): the
// single-peer edge/hub mints exactly one (the primary) from the sole configured psk, while
// the concentrator mints one per bound peer from that peer's DIFFERENT effective psk, so a
// peerState built from a different psk gets its own codec/reflector and cross-psk frames are
// rejected. virt is created here (not per Open) because the concentrator pins its destination
// once for the process life. The Reflector draws its per-path challenges from crypto/rand,
// exactly as before. The per-Open fields (sendCodec, paths, resequencer, FEC planes) are
// left zero for Open to (re)build.
func newPeerState(name string, psk config.Key, scheduler sched.Scheduler, newProber ProberFactory, probers []*telemetry.Prober) *peerState {
	return &peerState{
		name:      name,
		psk:       psk,
		virt:      &udpEndpoint{},
		scheduler: scheduler,
		reflector: telemetry.NewReflector(psk, rand.Reader),
		newProber: newProber,
		probers:   probers,
	}
}

// newCodec derives a fresh frame Codec bound to THIS peer's psk — the send Codec at Open and
// each per-(peer,path) receive Codec share the derivation but not the instance, since a Codec
// is not safe for concurrent use (each receive path decodes on its own goroutine). Deriving
// from ps.psk (not a Multipath-wide key) is what makes a path's receive Codec the codec of the
// peer the path is bound to (T84).
func (ps *peerState) newCodec() (*frame.Codec, error) {
	return frame.NewCodec(ps.psk)
}

// deferredPath is a configured path whose WELL-FORMED source_addr was not yet
// assignable at Open (net.ListenUDP -> EADDRNOTAVAIL: no interface holds the
// address, e.g. a 5G modem with no DHCP lease at boot). Rather than tear the whole
// bond down, Open records the path here instead of binding it: the tunnel comes up
// on the paths that DID bind, and this path stays DOWN — its prober, never fed an
// echo, reports StateDown, which the scheduler excludes from Pick, exactly as the
// runtime path-down model treats a live-but-silent path. It carries the boot-time
// prober so the T55 background reconcile that retries the bind reuses the SAME
// path-id stamp instead of minting a new one. prober is nil only on a bind without
// the probe transport, which never defers (see Open).
type deferredPath struct {
	def    config.Path
	prober *telemetry.Prober
}

func (ps *peerPathState) setRemote(ap netip.AddrPort) {
	ps.mu.Lock()
	ps.remote, ps.hasRemote = ap, true
	ps.mu.Unlock()
}

func (ps *peerPathState) getRemote() (netip.AddrPort, bool) {
	ps.mu.Lock()
	defer ps.mu.Unlock()
	return ps.remote, ps.hasRemote
}

// Multipath is the P1 bonding conn.Bind: one UDP socket per configured path
// (bound to the path's source address), all fronted by a SINGLE stable virtual
// endpoint the engine holds per peer. Send wraps each opaque WireGuard datagram
// in an outer DATA frame (own outer-seq + path-id) and picks a path; one
// Bind-owned reader per path unwraps DATA frames into the shared resequencer, and
// a SINGLE engine-facing ReceiveFunc drains it and hands the inner WG datagram up
// under the shared virtual endpoint (the fan-in that lets paths be added/removed at
// runtime without the engine spawning receive goroutines — T30). It replaces
// bind.Passthrough behind the same conn.Bind seam (device wiring is unchanged).
//
// Lifecycle: the sockets live for the duration of an Open→Close span, NOT the
// Multipath's whole life. The amneziawg engine calls Close() before every Open()
// (device.upLocked → BindUpdate → closeBindLocked, and on IpcSet listen_port /
// route-change events) and cycles Close↔Open on Down/Up, so — exactly like
// conn.StdNetBind — Open creates the per-path sockets and Close tears them down
// AND clears the path state so the next Open rebuilds from scratch. The "closed"
// state is simply "no bound sockets" (len(paths)==0); there is no separate sticky
// flag that a later Open would have to reset.
//
// Path policy: an injected sched.Scheduler (T15) chooses the egress path per
// datagram. The P1 MVP wires an active-backup scheduler (all traffic on the
// preferred primary, transparent failover to a backup on a T13 path-DOWN signal
// with failback hysteresis); the weighted/FEC-aware policy (T21) is a different
// Scheduler swapped in here with no Bind change. No FEC/resequencing yet
// (P2/P3), but every DATA frame carries its outer-seq and path-id so T18/T24 can
// consume them.
// ProberFactory mints a *telemetry.Prober for a path admitted at runtime (T30),
// stamped with the given stable path-id. The device wires it capturing the SAME
// per-boot session id, prober config, clock, PSK, and logger the boot-time probers
// were built with, so a runtime path's liveness is measured identically to a
// boot-time path (its probes join the same session so the peer's reflector adopts
// them without a challenge reset). It is nil on a bind built without the probe
// transport (the T12 unit tests), which therefore cannot add paths at runtime.
type ProberFactory func(name string, id uint8) *telemetry.Prober

// sourceBinding is one entry of the source->peer demux map (peerBySource): the peer a learned
// source AddrPort was bound to by an authenticated PROBE, plus a monotonic insertion sequence
// used ONLY to choose a peer's OWN oldest binding for LRU eviction when that peer authenticates
// a new AddrPort for itself while already at its per-peer quota (roam port-churn, D49). The seq
// orders a single peer's own bindings against each other; it is never compared across peers.
type sourceBinding struct {
	peer *peerState
	seq  uint64
}

type Multipath struct {
	defs []config.Path

	// classify maps each outbound datagram to its pacer traffic class from the inner
	// WireGuard message type, parameterized by the tunnel's Amnezia obfuscation profile
	// so a WireGuard control frame (handshake/keepalive) is recognised — and pacing-
	// exempted — under advanced security too, not only in vanilla mode (defect D22). It
	// is immutable after construction and holds no lock, so Send reads it off m.mu.
	classify wgClassifier

	// deferredListen binds a reconciled deferred path's socket (T55 background
	// reconcile). It is an injection seam: the default pins the source IP unless dev is
	// set (net.ListenUDP / listenPath, matching AddPath's runtime bind — I5), and a test
	// overrides it to drive the deferred→bound transition deterministically — a
	// source_addr "becoming assignable" — without a real interface address having to
	// appear on the host. dev is resolveForcedDeviceBind's decision for the deferred
	// path's resolved BindMode, computed by reconcileDeferred before the call. Immutable
	// after construction, never nil.
	deferredListen func(src netip.Addr, port uint16, dev string) (*net.UDPConn, error)

	// resolveDeviceBind decides AddPath's and reconcileDeferred's per-path forced-
	// device bind (I5): whether a path's RESOLVED BindMode is config.BindModeDevice,
	// and if so, the interface its source_addr currently resolves to (see
	// resolveForcedDeviceBind — it has no other-path contention to check, unlike
	// Open's planPathBinds/selectDeviceBinds). It is an injection seam mirroring
	// deferredListen: the default is the real resolveForcedDeviceBind (a
	// net.Interfaces() snapshot), and a test overrides it to drive a BindModeDevice
	// path's dev deterministically without a real interface having to appear on the
	// host (T106 round 2). Immutable after construction, never nil.
	resolveDeviceBind func(src netip.Addr, mode config.BindMode) string

	// addPathListen binds AddPath's runtime-admitted path's socket. It is an
	// injection seam mirroring deferredListen, scoped to AddPath's OWN call site:
	// AddPath calls the package-level listenPath directly (it is not routed through
	// deferredListen, which only reconcileDeferred drives), so without this seam no
	// test can observe what dev AddPath actually threads into the bind — resolving a
	// BindModeDevice interface via resolveDeviceBind and then discarding it at the
	// listen call passes the full suite (T106 round 3). The default is the real
	// listenPath; a test overrides it to capture the dev argument deterministically
	// without a real interface having to appear on the host. Immutable after
	// construction, never nil.
	addPathListen func(src netip.Addr, port uint16, dev string) (*net.UDPConn, error)

	mu sync.Mutex

	// The PRIMARY peer, embedded so the single-peer datapath (Send, the receive drainer,
	// the probe loop) and the existing single-peer tests reach its fields — virt,
	// scheduler, reflector, newProber, probers, sendCodec, paths, outerSeq, resequencer,
	// fecSend/fecRecv — transparently through promotion, keeping behaviour byte-identical
	// to the pre-split singleton. It is peers[0]; the concentrator's additional peers live
	// in peers/peersByName. The former process-global resequencer/outerSeq/scheduler now
	// live on this peerState, NOT on Multipath.
	*peerState

	// peers is every bound peer (len 1 on the single-peer edge/hub). The runtime shared-
	// path add/remove fan-out iterates it so per-(peer,path) state is created/torn-down for
	// EVERY currently-bound peer (attachSharedPathLocked / RemovePath). peersByName keys
	// them by peer id/name.
	peers       []*peerState
	peersByName map[string]*peerState
	// peersView is the LOCK-FREE snapshot of the bound peer set the single engine-facing
	// receive drainer iterates (newReceiveFunc). m.peers is mutated only under m.mu (peer
	// wiring / fan-out); every mutation republishes this pointer (republishPeersLocked) so
	// the drainer enumerates EVERY bound peer's resequencer WITHOUT taking m.mu on the
	// receive hot path — the same lock-free-publish discipline resequencer/fecRecv use. It
	// is never nil after construction (the constructor publishes the primary-only view).
	peersView atomic.Pointer[[]*peerState]
	// peerByEndpoint is the inbound endpoint-keyed demux placeholder (still unused today: the
	// single-peer edge/hub needs no demux, and the source-keyed binding below is what the
	// concentrator receive path routes on).
	peerByEndpoint map[netip.AddrPort]*peerState
	// peerBySource is the inbound source-demux map: a learned source AddrPort → the peer it was
	// bound to by an authenticated PROBE (T88). It is keyed by the full source netip.AddrPort
	// (address+port, D47), NOT the bare address, so two peers behind ONE public IP (CGNAT, one
	// netip.Addr, distinct ports) occupy distinct entries and demux independently. The
	// concentrator's per-socket readLoops resolve a datagram's source to its owning peer through
	// it; a source is bound ONLY on the first PROBE that MAC-verifies under a peer's psk (D9/D11:
	// bindings, like remotes, are learned only from authenticated PROBEs). It is published
	// copy-on-write through an atomic.Pointer so the receive hot path resolves a bound source with
	// a lock-free Load (no m.mu — a reader must never block on m.mu, since Close waits on the
	// readers WHILE holding it), and a new binding is installed lock-free by a CAS republish of a
	// copy with the entry added (bindSourceToPeer). Nil until the first binding; the single-peer
	// edge/hub never consults it (one peer owns every socket — handleInbound's fast path skips the
	// demux entirely).
	peerBySource atomic.Pointer[map[netip.AddrPort]sourceBinding]
	// maxDemuxSources is the GLOBAL cap on peerBySource (the provisional/unbound-source demux
	// state) so a bootstrap flood cannot grow it without bound (Q26/Q27, see defaultMaxDemuxSources).
	// Within it bindSourceToPeer enforces a PER-PEER quota (maxDemuxSources/len(peers), floor 1,
	// D49) for cross-peer isolation. Set once at construction and read on the lock-free bind path
	// (bindSourceToPeer); a test may lower it to exercise cap/quota exhaustion. Zero (never set)
	// means "no cap".
	maxDemuxSources int
	// bindSeq is a monotonic counter stamped on each source binding to order a peer's OWN
	// bindings for per-peer LRU eviction (D49 roam port-churn). Read/incremented on the lock-free
	// bind path (bindSourceToPeer) from readLoop goroutines, so it is atomic; it takes no m.mu.
	bindSeq atomic.Uint64
	// peerByVirt routes an OUTBOUND Send to its owning peer: the engine hands Send the
	// single virtual endpoint (*udpEndpoint) it holds for a peer, and this map resolves
	// that pointer to the peer's datapath state (outerSeq, scheduler, sendCodec, fecSend,
	// per-(peer,path) set). It is the SEND-side dual of peerByEndpoint/peerBySource (which
	// demux INBOUND datagrams). Each peer's virt is DISTINCT, so the lookup is exact; an
	// endpoint not in this map is an unknown peer, which Send refuses rather than
	// misrouting onto some other peer's paths. The primary is registered at construction;
	// the concentrator registers each additional peer as it binds it. Read under m.mu on
	// the Send path; written under m.mu (or at single-threaded construction).
	peerByVirt map[*udpEndpoint]*peerState

	// shared is the SHARED per-socket path list (the sockets themselves), rebuilt from
	// m.defs on every Open and mutated by the runtime add/remove. Each bound peer holds a
	// peerPathState VIEW over a subset of these; on the single-peer edge/hub primary.paths
	// is index-aligned with shared. len(shared)==0 is the "closed" (no sockets) state.
	shared []*sharedPathState

	// deferred holds the configured paths whose well-formed source_addr was not yet
	// assignable at the last Open (EADDRNOTAVAIL). They are NOT in shared or the
	// scheduler — the tunnel runs on the paths that bound — but are recorded here,
	// index-independent of shared, for the T55 background reconcile to retry as their
	// addresses appear. Rebuilt from scratch on every Open; guarded by m.mu. The deferred-
	// path machinery is SHARED (per-socket): a promoted deferred path fans its per-(peer,
	// path) state out to every peer exactly as a runtime AddPath does.
	deferred []deferredPath
	// defaultRemote is the fallback per-path remote (the peer's wireguard
	// endpoint) applied to any path without its own dest_addr. It may be set by
	// ParseEndpoint BEFORE Open, so it is stored here and applied at Open time.
	defaultRemote    netip.AddrPort
	hasDefaultRemote bool

	// fecCfg / adaptiveCfg are the FEC configuration (T24/T29), shared by every peer; the
	// per-peer fecSend/fecRecv runtime state Open builds from them lives on peerState. nil
	// when FEC (respectively adaptive FEC) is disabled — the datapath is then byte-for-byte
	// the pre-T24 behaviour. See fec.go.
	fecCfg      *fec.Config
	adaptiveCfg *adaptivefec.Config

	// Receive fan-in (T30). To let a path be added at runtime WITHOUT the engine
	// spawning a new receive goroutine (it only builds its receive goroutines once,
	// from the ReceiveFuncs Open returns), the per-path socket reads are decoupled
	// from the engine-facing delivery: the Bind owns one readLoop goroutine PER path
	// (tracked by readersWG) that reads its socket and feeds the shared resequencer,
	// and Open returns a SINGLE engine-facing ReceiveFunc that drains the resequencer
	// in order. A reader pokes deliverSignal after each datagram so the drainer wakes;
	// recvClosed is closed by Close to release both the drainer and any reader parked
	// on a delivery. openPort mirrors Open's bind port so a runtime-added path binds
	// consistently; nextPathID is a monotonic high-water that persists ACROSS Open
	// spans (a Close->Open never lowers it; only a process restart resets it), so a
	// surviving path is never renumbered and a freed id is never reused for the
	// process lifetime, and thus can never collide with the peer's per-path reflector
	// state.
	deliverSignal chan struct{}
	recvClosed    chan struct{}
	readersWG     sync.WaitGroup
	openPort      uint16
	nextPathID    uint16

	// Receive-path liveness sweep (T39, defect D15). Liveness DOWN-detection normally
	// rides StartProbeLoop's single wall-clock ticker goroutine (emitProbes → Tick).
	// Under heavy CPU load — e.g. the concentrator absorbing a saturating forward flood
	// on 4 vCPU — that timer goroutine can be scheduled with ~1s jitter, delaying a
	// path-DOWN transition (and thus the reply-direction failover) past the P1 budget.
	// The per-path receive goroutines, in contrast, are the goroutines the inbound
	// traffic is ALREADY scheduling, so driving Tick from them re-evaluates liveness
	// even when the timer goroutine is starved. sweepIntervalNanos is the probe
	// interval (0 until StartProbeLoop arms it — a bind without the probe transport
	// never sweeps); lastSweepNanos is the wall-clock high-water throttling the sweep
	// to at most once per interval so the receive hot path stays cheap.
	sweepIntervalNanos atomic.Int64
	lastSweepNanos     atomic.Int64

	// everUp is the STICKY "ever had a live path" predicate (I4): set true the first time
	// ANY path, for ANY bound peer, reaches liveness telemetry.StateUp (dispatchInbound,
	// on a fresh probe echo), and never cleared afterward — a later total outage is a
	// genuine failure signal, not a startup warmup. The device-package engineLogger
	// adapter consults EverHadLivePath to downgrade the startup no-healthy-path spam
	// (ErrNoHealthyPath) to a single coalesced INFO line until the first path comes up,
	// then lets it log at ERROR (a real outage) from then on.
	everUp atomic.Bool

	// onFirstPathUp is the optional injectable one-shot callback (D37 detection seam):
	// invoked EXACTLY ONCE, off the receive hot path, on the everUp latch's false->true
	// edge — the SAME moment EverHadLivePath starts reporting true. It keeps the bind
	// WG-unaware: dispatchInbound invokes an opaque func() rather than importing
	// anything from the device/engine layer, so the device-layer consumer (the
	// dependent task) wires whatever it needs (e.g. nudging the engine) through this
	// closure. nil (the default, set by NewMultipath) means "no callback" — dispatchInbound
	// checks for nil before invoking it, so an unset callback never panics. Set via
	// SetOnFirstPathUp; read lock-free (atomic.Pointer) so the receive hot path never
	// blocks on m.mu to check it.
	onFirstPathUp atomic.Pointer[func()]
}

// compile-time proof that Multipath satisfies the engine's Bind contract.
var _ Bind = (*Multipath)(nil)

// NewMultipath returns a closed multipath Bind over the configured paths; call
// Open to bind the per-path sockets. The PSK keys the outer framing and must be
// set (config validation guarantees it). The scheduler is the injected send-side
// path-selection policy (T15) whose priority order MUST match the paths slice
// order (index 0 = the preferred primary); it is a required collaborator so the
// send path is never without a policy.
//
// probers is the per-path probe initiator that drives on-wire liveness (T13/T37).
// When non-nil it MUST hold exactly one *telemetry.Prober per path, in path order,
// and those SAME values MUST be the scheduler's PathHealth sources so the liveness
// the probe loop measures is the liveness the scheduler selects on. Pass nil to
// run the bind without the probe transport (the T12 unit tests drive selection via
// sched.AlwaysUp instead). A Reflector is built from the PSK to answer peer probes.
//
// newProber is the factory the runtime path-add path (AddPath, T30) uses to mint a
// prober for a newly-admitted path; it must be non-nil to allow AddPath and MUST be
// paired with a non-nil probers (the boot-time set) — a factory without a boot-time
// slice would let AddPath append to a nil m.probers, breaking the m.paths/m.probers
// alignment invariant and panicking on the next Open at m.probers[i]. Pass nil to
// forbid runtime path addition.
//
// fecCfg is the fixed-ratio Reed-Solomon FEC configuration (T24). Pass nil to run the
// datapath with FEC disabled (the pre-T24 behaviour, byte-for-byte); a non-nil,
// pre-validated config turns the send-side parity encoder and receive-side recovery
// decoder on. It is validated here (fail fast) so an invalid ratio is rejected at
// construction rather than at the first Open.
// adaptiveCfg is the adaptive-FEC controller configuration (T29). Pass nil for the
// fixed-ratio behaviour (T24); a non-nil config REQUIRES a non-nil fecCfg (the
// controller resizes the FEC encoder's parity — it is meaningless with the plane off)
// and reinterprets fecCfg.ParityShards as the controller's parity ceiling. It is
// validated here (fail fast) so a mis-tuned control law is rejected at construction.
//
// amnezia is the tunnel's AmneziaWG obfuscation profile (config.Amnezia). It
// parameterizes the send-path frame-type classifier so a WireGuard control frame is
// recognised and pacing-exempted under advanced security — custom magic headers and
// handshake junk prefixes — as well as in vanilla mode (defect D22). Pass the zero value
// for a vanilla (unobfuscated) tunnel; the classifier then uses the default type words
// and no junk prefix. It does NOT need to match the config's validated state — an
// all-zero profile is exactly the vanilla classifier.
func NewMultipath(paths []config.Path, psk config.Key, scheduler sched.Scheduler, probers []*telemetry.Prober, newProber ProberFactory, fecCfg *fec.Config, adaptiveCfg *adaptivefec.Config, amnezia config.Amnezia) (*Multipath, error) {
	if len(paths) == 0 {
		return nil, errors.New("bind: at least one path is required")
	}
	if !psk.IsSet() {
		return nil, errors.New("bind: PSK is required for outer framing")
	}
	if len(paths) > 256 {
		// path-id is a uint8 in the DATA frame header.
		return nil, fmt.Errorf("bind: at most 256 paths supported, got %d", len(paths))
	}
	if scheduler == nil {
		return nil, errors.New("bind: a send scheduler is required")
	}
	if newProber != nil && probers == nil {
		// A runtime-path factory without a boot-time prober slice would let AddPath append
		// to a nil m.probers, desyncing m.paths from m.probers and panicking on the next
		// Open at m.probers[i]. The two are paired by construction; enforce it here.
		return nil, errors.New("bind: newProber requires a non-nil probers (boot-time set)")
	}
	if probers != nil && len(probers) != len(paths) {
		return nil, fmt.Errorf("bind: probers must have one entry per path (got %d, want %d)", len(probers), len(paths))
	}
	for i, pr := range probers {
		if pr == nil {
			return nil, fmt.Errorf("bind: prober %d is nil", i)
		}
	}
	if fecCfg != nil {
		if err := fecCfg.Validate(); err != nil {
			return nil, fmt.Errorf("bind: invalid FEC configuration: %w", err)
		}
		if fecCfg.Deadline > maxFECDeadline {
			// A deadline this large makes every deadline-flushed group's recovery
			// structurally late: the resequencer skips the gap (resequencerTimeout) before
			// the parity-derived frames land, so recovery never delivers. Reject it rather
			// than ship a bond whose FEC silently cannot help (defect #4).
			return nil, fmt.Errorf("bind: fec deadline %s exceeds the max %s (must stay safely below the resequencer's %s per-gap timeout so deadline-flushed recovery lands before the gap is skipped)", fecCfg.Deadline, maxFECDeadline, resequencerTimeout)
		}
	}
	if adaptiveCfg != nil {
		if fecCfg == nil {
			return nil, errors.New("bind: adaptive FEC requires a FEC configuration (the controller resizes the FEC encoder's parity)")
		}
		if err := adaptiveCfg.Validate(); err != nil {
			return nil, fmt.Errorf("bind: invalid adaptive FEC configuration: %w", err)
		}
		// The controller's parity ceiling (MaxParity) is the fixed FEC ParityShards both
		// ends agree on: the receiver's decoder is built at fecCfg.ParityShards, and the
		// encoder must never emit more parity than that ceiling (SetParity clamps to it).
		// A mismatch would let the controller target a parity index the decoder rejects,
		// so bind the two together at construction rather than trusting the caller.
		if adaptiveCfg.MaxParity != fecCfg.ParityShards {
			return nil, fmt.Errorf("bind: adaptive FEC parity ceiling (MaxParity=%d) must equal the FEC parity_shards (%d), which the receiver's decoder is built at", adaptiveCfg.MaxParity, fecCfg.ParityShards)
		}
		if adaptiveCfg.DataShards != fecCfg.DataShards {
			return nil, fmt.Errorf("bind: adaptive FEC DataShards (%d) must equal the FEC data_shards (%d)", adaptiveCfg.DataShards, fecCfg.DataShards)
		}
	}
	// The single-peer edge/hub constructs EXACTLY ONE peerState (the primary). virt is
	// created here — NOT per Open — because the concentrator pins its destination once for
	// the process life and every existing test relies on the virtual-endpoint pointer being
	// stable across Open/Close/add/remove.
	primary := newPeerState("", psk, scheduler, newProber, probers)
	m := &Multipath{
		defs:              append([]config.Path(nil), paths...),
		classify:          newWGClassifier(amnezia),
		deferredListen:    defaultDeferredListen,
		resolveDeviceBind: resolveForcedDeviceBind,
		addPathListen:     listenPath,
		peerState:         primary,
		peers:             []*peerState{primary},
		peersByName:       map[string]*peerState{primary.name: primary},
		peerByEndpoint:    map[netip.AddrPort]*peerState{},
		peerByVirt:        map[*udpEndpoint]*peerState{primary.virt: primary},
		maxDemuxSources:   defaultMaxDemuxSources,
		fecCfg:            fecCfg,
		adaptiveCfg:       adaptiveCfg,
	}
	// Publish the initial (primary-only) peer view the receive drainer iterates. No
	// concurrency yet — the bind is not open — so this runs without m.mu.
	m.republishPeersLocked()
	return m, nil
}

// republishPeersLocked snapshots m.peers into the lock-free peersView the engine-facing
// receive drainer (newReceiveFunc) iterates. The caller MUST hold m.mu whenever the bind
// can be open (so the snapshot never races a concurrent m.peers append); the constructor
// is the sole exception (it runs before the Multipath is reachable by any goroutine). The
// snapshot is a fresh slice so a later append to m.peers never mutates a view the drainer
// is mid-iteration over.
func (m *Multipath) republishPeersLocked() {
	snap := make([]*peerState, len(m.peers))
	copy(snap, m.peers)
	m.peersView.Store(&snap)
}

// AddConcentratorPeer registers one ADDITIONAL bound peer with the Bind — the concentrator's
// per-peer wiring (G4/T93). Peer 0 (the embedded primary) is built by NewMultipath; the
// concentrator calls this once per additional configured peer, each with its OWN effective psk,
// send scheduler, boot-time per-path prober set, and runtime prober factory (all keyed on that
// peer's psk, so one peer's codec/reflector reject another's frames — T84/R72). The peer's
// STABLE virtual endpoint is minted here (newPeerState) and registered in peerByVirt so an
// outbound Send routes replies back to THIS peer; Open then builds this peer's per-(peer,path)
// view of every bound socket, reconciles its scheduler, and (via newReceiveFunc) reports its
// virt to the engine on the first inbound frame (invariant A1: one virtual endpoint per peer).
//
// It MUST be called BEFORE Open (while the bind is closed): the per-(peer,path) views are
// rebuilt by Open from the registered peer set on every Open span (including each Close→Open
// cycle the engine drives on Down/Up and route changes), so a peer registered after the sockets
// are bound would be view-less and its DATA/PROBE never routed. probers, when supplied, must be
// index-aligned with the configured path membership (m.defs), exactly as the primary's are.
func (m *Multipath) AddConcentratorPeer(name string, psk config.Key, scheduler sched.Scheduler, probers []*telemetry.Prober, newProber ProberFactory) error {
	if name == "" {
		return errors.New("bind: concentrator peer name is required")
	}
	if !psk.IsSet() {
		return errors.New("bind: concentrator peer psk is required")
	}
	if scheduler == nil {
		return errors.New("bind: concentrator peer requires a send scheduler")
	}
	if newProber != nil && probers == nil {
		return errors.New("bind: newProber requires a non-nil probers (boot-time set)")
	}
	m.mu.Lock()
	defer m.mu.Unlock()
	if len(m.paths) != 0 {
		return errors.New("bind: concentrator peers must be registered before Open")
	}
	if probers != nil && len(probers) != len(m.defs) {
		return fmt.Errorf("bind: concentrator peer %q: probers must have one entry per configured path (got %d, want %d)", name, len(probers), len(m.defs))
	}
	for i, pr := range probers {
		if pr == nil {
			return fmt.Errorf("bind: concentrator peer %q: prober %d is nil", name, i)
		}
	}
	if name == m.name {
		return fmt.Errorf("bind: concentrator peer name %q collides with the primary peer", name)
	}
	if _, dup := m.peersByName[name]; dup {
		return fmt.Errorf("bind: duplicate concentrator peer name %q", name)
	}
	p := newPeerState(name, psk, scheduler, newProber, probers)
	m.peers = append(m.peers, p)
	m.peersByName[name] = p
	m.peerByVirt[p.virt] = p
	// Publish the grown peer set so the engine-facing receive drainer (newReceiveFunc) will
	// enumerate this peer's resequencer once Open builds it.
	m.republishPeersLocked()
	return nil
}

// Open binds one UDP socket per configured path to that path's source address on
// port (0 = random per socket), sets a large SO_RCVBUF on each, spawns one
// Bind-owned reader per path, and returns a SINGLE engine-facing ReceiveFunc (the
// fan-in drainer) plus the first path's bound port. Each path whose config carries
// a dest_addr — or, failing that, the peer's wireguard endpoint learned via
// ParseEndpoint — starts with a known remote; the rest are learned from inbound
// traffic.
//
// Open is the sole creator of the per-path sockets: the engine's bring-up path
// calls Close() first (on the still-unopened bind) and then Open(), so building
// the sockets HERE — not in NewMultipath — is what makes that Close→Open sequence
// (and every subsequent Down→Up) work. The engine passes the previously-bound
// port back on a re-Open; each path binds to it on its own distinct source
// address, and the first path's bound port is returned so the engine keeps a
// stable listen port across the cycle (matching conn.StdNetBind).
func (m *Multipath) Open(port uint16) ([]ReceiveFunc, uint16, error) {
	m.mu.Lock()
	defer m.mu.Unlock()
	if len(m.paths) != 0 {
		return nil, 0, conn.ErrBindAlreadyOpen
	}

	// (Re)build the per-Open datapath planes — send Codec, receive resequencer, and FEC
	// send/receive state — fresh for this bring-up, for EVERY bound peer (not just the
	// primary via promotion). This keeps Open symmetric with closeSocketsLocked, which
	// clears every peer's per-Open state: a concentrator peer bound before Open must get
	// its OWN fresh planes on each Close→Open cycle, and one peer's (re)creation must never
	// touch another peer's release point or FEC group state. On the single-peer edge/hub
	// m.peers holds only the primary, so this is byte-identical to the pre-split rebuild.
	// See openPeerDatapathLocked.
	for _, p := range m.peers {
		if err := m.openPeerDatapathLocked(p); err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, err
		}
	}

	// Resolve every path's interface up front and decide, per path, whether its
	// socket may be device-bound (SO_BINDTODEVICE + wildcard — survives a T16
	// re-roam) or must pin the specific source IP (the pre-T16 behaviour, required
	// when paths share an interface or the interface is multi-address, so distinct
	// specific-IP sockets coexist on one port without an EADDRINUSE collision). See
	// selectDeviceBinds.
	srcs := make([]netip.Addr, len(m.defs))
	modes := make([]config.BindMode, len(m.defs))
	for i := range m.defs {
		srcs[i] = m.defs[i].SourceAddr
		modes[i] = m.defs[i].Bind
	}
	bindDevs := planPathBinds(srcs, modes)

	// A path whose WELL-FORMED source_addr is merely NOT-YET-ASSIGNABLE at boot
	// (EADDRNOTAVAIL: no interface holds the address — a 5G modem without a DHCP
	// lease, Starlink mid-obstruction) is DEFERRED rather than treated as fatal, so
	// the bond comes up on the paths that DO bind (G2/W1, approach A). Tolerating it
	// requires the runtime path-down machinery: the deferred path's prober stays
	// StateDown so the scheduler excludes it, and a DynamicScheduler whose membership
	// can be reconciled to only the bound paths. Absent the probe transport (the T12
	// no-prober unit binds) or a dynamic scheduler there is no such Down model, so —
	// exactly as AddPath refuses a runtime add without probers — every bind error
	// stays fatal there. A MALFORMED source_addr never reaches here (config.validate
	// rejects it at load), and any OTHER bind error (EADDRINUSE, permission) is fatal.
	_, dynOK := m.scheduler.(sched.DynamicScheduler)
	tolerateDefer := m.probers != nil && dynOK
	m.deferred = nil

	actualPort := port
	firstBound := true
	for i := range m.defs {
		def := m.defs[i]
		// Device-bind this path when selectDeviceBinds proved it safe (so a
		// mid-session source-address change / T16 re-roam does not break the socket),
		// otherwise pin the specific source IP. See selectDeviceBinds / listenPath.
		c, err := listenPath(def.SourceAddr, port, bindDevs[i])
		if err != nil {
			if tolerateDefer && errors.Is(err, syscall.EADDRNOTAVAIL) {
				// Defer this path: record its def + boot prober (kept Down) for the T55
				// background reconcile to retry, and leave the bond to come up on the rest.
				// Mirrors AddPath's rollback discipline — a failed path never disturbs the
				// tunnel — at the boot boundary.
				m.deferred = append(m.deferred, deferredPath{def: def, prober: m.probers[i]})
				continue
			}
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: open path %q on %s: %w", def.Name, def.SourceAddr, err)
		}
		// Large SO_RCVBUF, best-effort: the kernel caps at net.core.rmem_max and
		// SetReadBuffer does not require privilege, so a returned error is rare;
		// treat it as non-fatal rather than refusing to bind in a restricted env.
		_ = c.SetReadBuffer(socketRecvBuffer)

		shared := &sharedPathState{name: def.Name, id: uint8(i), src: def.SourceAddr, conn: c}
		// Build EVERY bound peer's view of this shared socket (T93): each peer decodes under its
		// OWN psk-derived Codec and probes with its OWN per-(peer,path) prober, so a concentrator
		// socket shared by several peers keeps each peer's authenticated stream isolated
		// (demuxInbound source-demuxes on the first authenticated PROBE). The primary (peers[0])
		// is built exactly as the pre-split single peer — byte-identical on the single-peer
		// edge/hub, where m.peers holds only the primary. m.paths (the primary's path slice,
		// reached through the embed) grows via the pi==0 append below; a concentrator peer's
		// paths grow on its own peerState.
		for pi, p := range m.peers {
			// The path binds to peer p; its receive codec is p's codec (derived from p's psk).
			codec, err := p.newCodec()
			if err != nil {
				_ = c.Close()
				_ = m.closeSocketsLocked()
				return nil, 0, err
			}
			pp := &peerPathState{sharedPathState: shared, peer: p, codec: codec}
			if p.probers != nil {
				// Fail fast rather than panic if a peer's prober slice ever falls short of the
				// shared m.defs membership: every runtime admission (bound OR deferred) fans a
				// per-peer prober out to EVERY peer (AddPath), so p.probers stays index-aligned
				// with m.defs. A divergence is a wiring defect — surface it as a bind error
				// instead of an index-out-of-range panic that would crash the daemon.
				if i >= len(p.probers) {
					_ = c.Close()
					_ = m.closeSocketsLocked()
					return nil, 0, fmt.Errorf("bind: peer %q prober set (len %d) is shorter than the path membership at index %d — per-peer prober fan-out desync", p.name, len(p.probers), i)
				}
				pp.prober = p.probers[i]
				if pi == 0 {
					// Reconcile the SHARED DATA-frame path-id to the PRIMARY prober's IMMUTABLE
					// stamp rather than the slice index i: after a runtime RemovePath the survivor
					// keeps its original (higher) stamp, so index-based numbering would renumber a
					// live path AND diverge its DATA id from its PROBE stamp. Every peer's
					// probers[i] carries the SAME stamp (the device stamps each peer's boot prober
					// for path i identically), so taking it from the primary is authoritative and
					// keeps DATA and every peer's PROBE agreeing on the wire.
					shared.id = pp.prober.PathID()
				}
			}
			switch {
			case def.DestAddr.IsValid():
				pp.setRemote(def.DestAddr)
			case m.hasDefaultRemote:
				pp.setRemote(m.defaultRemote)
			}
			p.paths = append(p.paths, pp)
			// Publish this peer's view for the receive demux (T88). A single-view socket is the
			// edge/hub byte-identical fast path in demuxInbound; a socket with >1 view is
			// source-demuxed to its owning peer on each authenticated PROBE.
			shared.addViewLocked(pp)
		}
		m.shared = append(m.shared, shared)
		if firstBound {
			actualPort = uint16(c.LocalAddr().(*net.UDPAddr).Port)
			firstBound = false
		}
	}

	// Hard guard (a): a bond with NO transport is impossible. If every configured path
	// deferred, tolerance must NOT degrade to a zero-path bind — fail fatally, exactly
	// as the pre-tolerance Open did when the sole path could not bind.
	if len(m.paths) == 0 {
		_ = m.closeSocketsLocked()
		return nil, 0, fmt.Errorf("bind: no configured path could bind its source address (all %d deferred as not-yet-assignable)", len(m.deferred))
	}

	// nextPathID is a MONOTONIC HIGH-WATER carried ACROSS Open spans, never decreased.
	// Close does not reset it, and here it is only ever RAISED to at least max(existing
	// path stamp)+1. Resetting it to len(m.paths) (the pre-fix behaviour) re-minted an id
	// a survivor still held once a RemovePath had opened a gap in the stamp space below
	// that survivor's stamp: the next runtime AddPath then collided with the live path at
	// an identical (PathID, SessionID), and because the peer's Reflector keys anti-replay
	// AND the session challenge PER PathID, the strict-monotonic replay filter dropped one
	// of the two independent ProbeSeq streams -> probe loss / false-DOWN. Deriving the
	// high-water from the (prober-stamped) ps.id covers both the probe-transport case and
	// the T12 no-prober case (where ps.id == i, so the high-water is len(m.paths)).
	m.openPort = port
	for _, ps := range m.paths {
		if uint16(ps.id)+1 > m.nextPathID {
			m.nextPathID = uint16(ps.id) + 1
		}
	}
	// A DEFERRED path's boot prober already OWNS its path-id stamp; raise the
	// high-water past it too, so a runtime AddPath arriving while the path is still
	// deferred cannot mint that reserved id and collide with it once T55 binds it.
	for _, dp := range m.deferred {
		if dp.prober != nil {
			if uint16(dp.prober.PathID())+1 > m.nextPathID {
				m.nextPathID = uint16(dp.prober.PathID()) + 1
			}
		}
	}

	// Reconcile the scheduler's membership with the path slice just rebuilt from
	// m.defs. A runtime AddPath/RemovePath (T30) keeps m.defs, m.probers, AND the
	// live scheduler in lockstep during an Open span; re-pinning the scheduler's
	// health list to the BOUND probers HERE — index-aligned with m.paths, since each
	// bound path appended its ps.prober to boundProbers in order above — is the single
	// reconciliation point that makes that runtime membership survive this
	// Close→Open cycle without a scheduler/path desync (no frozen zombie health
	// entry, no resurrected removed path). A DEFERRED path (not-yet-assignable
	// source_addr) is deliberately EXCLUDED here: its prober is absent from the
	// scheduler, so Pick can never select it, and Send's Pick->m.paths[idx] mapping
	// stays index-aligned with the bound-only path slice. Only meaningful with the
	// probe transport: a bind without probers cannot change membership at runtime
	// (AddPath is refused) and never defers, so its scheduler is left exactly as built.
	// Reconcile EACH bound peer's scheduler membership with the path slice just rebuilt from
	// m.defs (T93): every peer's per-(peer,path) views were appended in m.defs order above, so a
	// peer's scheduler health list is that peer's BOUND probers in order (a DEFERRED path
	// contributed no view and is deliberately excluded, exactly as for the primary). On the
	// single-peer edge/hub m.peers holds only the primary, so this reconciles exactly the one
	// scheduler — byte-identical to the pre-split single reconcile. A peer without the probe
	// transport or with a non-dynamic scheduler is left as built (the T12 no-prober unit binds
	// never change membership at runtime and never defer).
	for _, p := range m.peers {
		pdyn, pdynOK := p.scheduler.(sched.DynamicScheduler)
		if p.probers == nil || !pdynOK {
			continue
		}
		health := make([]sched.PathHealth, 0, len(p.paths))
		for _, pp := range p.paths {
			if pp.prober != nil {
				health = append(health, pp.prober)
			}
		}
		if err := pdyn.SetPaths(health); err != nil {
			_ = m.closeSocketsLocked()
			return nil, 0, fmt.Errorf("bind: reconcile scheduler on open: %w", err)
		}
	}

	// Stand up the receive fan-in: one Bind-owned reader per path feeding the shared
	// resequencer, and a single engine-facing drainer. Both channels are recreated
	// per Open so a Close→Open cycle starts clean.
	m.deliverSignal = make(chan struct{}, 1)
	m.recvClosed = make(chan struct{})
	for _, ps := range m.paths {
		m.readersWG.Add(1)
		go m.readLoop(ps, m.deliverSignal)
	}
	// Deadline-tick goroutine for FEC group close (T24): it flushes a partial group's
	// parity on time under low load so a group is never stranded waiting for the size
	// threshold. Tracked by readersWG (like the readers) so Close waits for it; it
	// exits on recvClosed. It TryLocks m.mu, so it never blocks Close's readersWG.Wait
	// held under m.mu.
	if m.fecSend.Load() != nil {
		m.readersWG.Add(1)
		go m.fecTickLoop(m.fecCfg.Deadline, m.recvClosed)
	}
	return []ReceiveFunc{m.newReceiveFunc(m.deliverSignal, m.recvClosed)}, actualPort, nil
}

// openPeerDatapathLocked (re)builds ONE peer's per-Open datapath planes: its send Codec
